export const AdminPanel = () => {
  const [unlocked, setUnlocked] = useState(false);
  const [checking, setChecking] = useState(true);

  // On mount, verify any cached token via /api/auth/me.
  useEffect(() => {
    let cancelled = false;
    (async () => {
      if (!getToken()) {
        if (!cancelled) setChecking(false);
        return;
      }
      try {
        await apiMe();
        if (!cancelled) setUnlocked(true);
      } catch {
        clearToken();
      } finally {
        if (!cancelled) setChecking(false);
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const handleUnlock = () => setUnlocked(true);
  const handleLogout = () => {
    clearToken();
    setUnlocked(false);
  };

  if (checking) {
    return (
      <div className="mx-auto max-w-6xl px-4 sm:px-6 py-20 text-center">
        <p className="text-sm text-neutral-600">Verifying admin session…</p>
      </div>
    );
  }

  return (
    <div className="mx-auto max-w-6xl px-4 sm:px-6 py-8 sm:py-14">
      <AnimatePresence mode="wait">
        {!unlocked ? (
          <PasswordGate key="gate" onUnlock={handleUnlock} />
        ) : (
          <Dashboard key="dash" onLogout={handleLogout} />
        )}
      </AnimatePresence>
    </div>
  );
};

const PasswordGate = ({ onUnlock }) => {
  const [pwd, setPwd] = useState("");
  const [err, setErr] = useState("");
  const [show, setShow] = useState(false);
  const [busy, setBusy] = useState(false);

  const submit = async (e) => {
    e.preventDefault();
    if (busy) return;
    if (!pwd) {
      setErr("Enter the master password.");
      return;
    }
    setBusy(true);
    setErr("");
    try {
      // Password-only flow — backend resolves identity from ADMIN_EMAIL env.
      const data = await apiLogin(pwd);
      if (data?.token) {
        setToken(data.token);
        onUnlock();
      } else {
        setErr("Login failed. Please try again.");
      }
    } catch (e2) {
      setErr(
        e2?.status === 401
          ? "Incorrect password."
          : e2?.message || "Login failed. Please try again.",
      );
    } finally {
      setBusy(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, y: -10 }}
      className="max-w-md mx-auto"
    >
      <div className="rounded-3xl border border-white/60 bg-white/75 backdrop-blur-2xl backdrop-saturate-150 shadow-[0_16px_48px_rgba(0,0,0,0.10)] p-8 sm:p-10">
        <div className="w-14 h-14 rounded-2xl bg-[#0B0C10] flex items-center justify-center mb-6">
          <Lock size={22} strokeWidth={1.6} className="text-white" />
        </div>
        <p className="text-xs uppercase tracking-[0.22em] text-[#064E3B] font-medium mb-2">
          Restricted · Admin
        </p>
        <h1 className="font-display text-3xl sm:text-4xl font-light text-[#0B0C10] mb-3">
          Enter the master key.
        </h1>
        <p className="text-sm text-neutral-600 mb-7">
          Only authorised staff can manage the MastiBazaar storefront and view
          customer orders.
        </p>

        <form onSubmit={submit} className="space-y-4">
          <div className="relative">
            <input
              data-testid={ADMIN.passwordInput}
              type={show ? "text" : "password"}
              value={pwd}
              onChange={(e) => setPwd(e.target.value)}
              placeholder="Master password"
              autoComplete="current-password"
              className="w-full bg-white/70 border border-white/60 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-2xl px-4 py-3.5 pr-12 text-sm transition-all"
              autoFocus
            />
            <button
              type="button"
              onClick={() => setShow((s) => !s)}
              data-testid="admin-password-toggle"
              className="absolute right-3 top-1/2 -translate-y-1/2 p-2 text-neutral-500 hover:text-[#0B0C10]"
              aria-label="toggle password visibility"
            >
              {show ? (
                <EyeOff size={16} strokeWidth={1.6} />
              ) : (
                <Eye size={16} strokeWidth={1.6} />
              )}
            </button>
          </div>
          {err && (
            <p
              data-testid={ADMIN.passwordError}
              className="text-xs text-red-500"
            >
              {err}
            </p>
          )}
          <button
            type="submit"
            disabled={busy}
            data-testid={ADMIN.unlockBtn}
            className="w-full bg-[#0B0C10] text-white rounded-full py-3.5 font-medium tracking-wide hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
          >
            {busy ? "Verifying…" : "Unlock admin"}
          </button>
        </form>
      </div>
    </motion.div>
  );
};

const Dashboard = ({ onLogout }) => {
  const [tab, setTab] = useState("products");
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [live, setLive] = useState(false);
  const [loading, setLoading] = useState(true);
  const [migrationOffer, setMigrationOffer] = useState(false);
  const [migrating, setMigrating] = useState(false);

  const reload = async () => {
    setLoading(true);
    try {
      const [p, o, l] = await Promise.all([
        getAllProducts(),
        getOrders(),
        isSiteLive(),
      ]);
      setProducts(p);
      setOrders(o);
      setLive(l);
    } catch (e) {
      toast.error(`Failed to load data: ${e.message}`);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    reload();
    // Offer migration if legacy localStorage data exists and has not been
    // migrated yet.
    if (!hasMigrated()) {
      const snap = readLegacySnapshot();
      const total =
        snap.products.length + snap.orders.length + snap.reviews.length;
      if (total > 0) setMigrationOffer(true);
      else markMigrated(); // nothing to migrate; suppress the prompt forever
    }
  }, []);

  const toggleLive = async () => {
    const next = !live;
    try {
      await setSiteLive(next);
      setLive(next);
    } catch (e) {
      toast.error(`Could not update site mode: ${e.message}`);
    }
  };

  const runMigration = async () => {
    setMigrating(true);
    const t = toast.loading("Importing browser data…");
    try {
      const snap = readLegacySnapshot();
      const res = await apiMigrate(snap);
      markMigrated();
      setMigrationOffer(false);
      toast.success(
        `Imported ${res.products} products · ${res.orders} orders · ${res.reviews} reviews`,
        { id: t, duration: 3200 },
      );
      await reload();
    } catch (e) {
      toast.error(`Import failed: ${e.message}`, { id: t });
    } finally {
      setMigrating(false);
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 16 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0 }}
      className="space-y-8"
    >
      <header className="flex flex-col sm:flex-row sm:items-end sm:justify-between gap-4">
        <div className="space-y-2">
          <p className="text-xs uppercase tracking-[0.22em] text-[#064E3B] font-medium">
            Control room
          </p>
          <h1 className="font-display text-4xl sm:text-5xl font-light text-[#0B0C10] tracking-tight">
            Admin panel.
          </h1>
          <p className="text-sm text-neutral-600">
            {loading
              ? "Loading…"
              : `${products.length} products · ${orders.length} orders`}
          </p>
        </div>
        <div className="flex items-center gap-2 self-start flex-wrap">
          <MaintenanceToggle live={live} onToggle={toggleLive} />
          <button
            onClick={onLogout}
            data-testid={ADMIN.logoutBtn}
            className="inline-flex items-center gap-2 bg-white/70 border border-white/60 text-[#0B0C10] rounded-full px-5 py-2.5 text-sm font-medium hover:bg-white transition-all"
          >
            <LogOut size={15} strokeWidth={1.6} />
            Lock
          </button>
        </div>
      </header>

      {migrationOffer && (
        <div
          data-testid="admin-migration-banner"
          className="rounded-3xl border border-[#E0B53C]/40 bg-[#FFF9E6] p-5 sm:p-6 flex flex-col sm:flex-row sm:items-center gap-4"
        >
          <div className="w-12 h-12 rounded-2xl bg-[#022C22] flex items-center justify-center shrink-0">
            <Download size={20} strokeWidth={1.6} className="text-[#E0B53C]" />
          </div>
          <div className="flex-1 min-w-0">
            <p className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
              Legacy data detected
            </p>
            <h3 className="font-display text-lg sm:text-xl text-[#0B0C10]">
              Import your browser data into the cloud.
            </h3>
            <p className="text-sm text-neutral-600">
              Products, orders and reviews still stored in this browser will be
              migrated to the backend and synced across devices.
            </p>
          </div>
          <div className="flex items-center gap-2 self-start sm:self-auto">
            <button
              onClick={runMigration}
              disabled={migrating}
              data-testid="admin-migration-run"
              className="inline-flex items-center gap-2 bg-[#022C22] text-[#E0B53C] rounded-full px-5 py-2.5 text-sm font-medium hover:bg-[#053f30] transition-all disabled:opacity-60"
            >
              {migrating ? "Importing…" : "Import now"}
            </button>
            <button
              onClick={() => {
                markMigrated();
                setMigrationOffer(false);
              }}
              disabled={migrating}
              data-testid="admin-migration-skip"
              className="text-xs uppercase tracking-[0.18em] font-medium text-neutral-500 hover:text-[#0B0C10] px-2 py-1"
            >
              Skip
            </button>
          </div>
        </div>
      )}

      <div className="flex gap-2 flex-wrap">
        <TabBtn
          testId={ADMIN.tabProducts}
          active={tab === "products"}
          onClick={() => setTab("products")}
          icon={<Package size={15} strokeWidth={1.6} />}
          label={`Products (${products.length})`}
        />
        <TabBtn
          testId={ADMIN.tabOrders}
          active={tab === "orders"}
          onClick={() => setTab("orders")}
          icon={<ShoppingBag size={15} strokeWidth={1.6} />}
          label={`Orders (${orders.length})`}
        />
        <TabBtn
          testId="admin-tab-banners"
          active={tab === "banners"}
          onClick={() => setTab("banners")}
          icon={<ImagePlus size={15} strokeWidth={1.6} />}
          label="Banners"
        />
        <TabBtn
          testId="admin-tab-folders"
          active={tab === "folders"}
          onClick={() => setTab("folders")}
          icon={<Folder size={15} strokeWidth={1.6} />}
          label="Folders"
        />
        <TabBtn
          testId="admin-tab-returns"
          active={tab === "returns"}
          onClick={() => setTab("returns")}
          icon={<RotateCcw size={15} strokeWidth={1.6} />}
          label="Returns"
        />
        <TabBtn
          testId="admin-tab-branding"
          active={tab === "branding"}
          onClick={() => setTab("branding")}
          icon={<Palette size={15} strokeWidth={1.6} />}
          label="Branding"
        />
      </div>

      {tab === "products" ? (
        <ProductsTab products={products} reload={reload} />
      ) : tab === "orders" ? (
        <OrdersTab orders={orders} reload={reload} />
      ) : tab === "folders" ? (
        <FoldersTab />
      ) : tab === "returns" ? (
        <ReturnsTab />
      ) : tab === "branding" ? (
        <BrandingTab />
      ) : (
        <BannerManager />
      )}
    </motion.div>
  );
};

