const ProductsTab = ({ products, reload }) => {
  const [form, setForm] = useState({
    title: "",
    price: "",
    originalPrice: "",
    category: CATEGORIES[0],
    description: "",
    image: "",
    sizes: "",
    colors: "",
    stockMap: {},
    // NEW additive: gallery of extra images (URL strings) + textual color names.
    images: [],
    colorNames: [],
  });
  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [stockEditFor, setStockEditFor] = useState(null);
  const [scheduleFor, setScheduleFor] = useState(null);
  // NEW additive: draft input strings for the dynamic gallery + color-name
  // tag widgets. Local UI state only — does not touch the existing form keys.
  const [imageDraft, setImageDraft] = useState("");
  const [colorNameDraft, setColorNameDraft] = useState("");
  // NEW additive: direct device-file upload state + refs. Lets the admin pick
  // a file from PC/phone/camera and the system uploads it to the backend in
  // the background, returning a public URL that fills the form automatically.
  // The existing URL field, cropper, and validation continue to work as-is.
  const [mainUploading, setMainUploading] = useState(false);
  const [galleryUploading, setGalleryUploading] = useState(false);
  const mainFileRef = useRef(null);
  const galleryFileRef = useRef(null);

  const readFileAsDataUrl = (file) =>
    new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result);
      reader.onerror = () => reject(reader.error || new Error("read failed"));
      reader.readAsDataURL(file);
    });

  const handleMainFile = async (e) => {
    const file = e.target.files?.[0];
    e.target.value = ""; // allow re-selecting the same file
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      toast.error("Please pick an image file.");
      return;
    }
    setMainUploading(true);
    const t = toast.loading("Uploading image…");
    try {
      const dataUrl = await readFileAsDataUrl(file);
      const url = await apiUploadIfDataUrl(dataUrl);
      setForm((p) => ({ ...p, image: url }));
      setErrors((er) => ({ ...er, image: undefined }));
      toast.success("Image uploaded", { id: t, duration: 1800 });
    } catch (err) {
      toast.error(`Upload failed: ${err?.message || "unknown"}`, { id: t });
    } finally {
      setMainUploading(false);
    }
  };

  const handleGalleryFiles = async (e) => {
    const files = Array.from(e.target.files || []);
    e.target.value = "";
    if (!files.length) return;
    setGalleryUploading(true);
    const t = toast.loading(
      files.length === 1 ? "Uploading image…" : `Uploading ${files.length} images…`,
    );
    let ok = 0;
    for (const file of files) {
      if (!file.type.startsWith("image/")) continue;
      try {
        const dataUrl = await readFileAsDataUrl(file);
        const url = await apiUploadIfDataUrl(dataUrl);
        setForm((p) => ({ ...p, images: [...p.images, url] }));
        ok += 1;
      } catch {
        // continue with remaining files; surface aggregated error below
      }
    }
    setGalleryUploading(false);
    if (ok === files.length) {
      toast.success(
        ok === 1 ? "Image added" : `${ok} images added`,
        { id: t, duration: 1800 },
      );
    } else if (ok > 0) {
      toast.warning(`Added ${ok}/${files.length} (some failed)`, { id: t });
    } else {
      toast.error("Upload failed", { id: t });
    }
  };

  const update = (k) => (e) =>
    setForm((p) => ({ ...p, [k]: e.target.value }));

  // Keep `stockMap` in sync with the sizes the admin enters. New sizes default
  // to 0; sizes removed from the input drop from the map.
  useEffect(() => {
    const sizes = form.sizes
      .split(",")
      .map((s) => s.trim())
      .filter(Boolean);
    setForm((p) => {
      const next = {};
      sizes.forEach((s) => {
        next[s] = Number.isFinite(p.stockMap?.[s]) ? p.stockMap[s] : 0;
      });
      return { ...p, stockMap: next };
    });
  }, [form.sizes]);

  const submit = async (e) => {
    e.preventDefault();
    const errs = {};
    if (!form.title.trim()) errs.title = "Title is required";
    if (!form.price || Number(form.price) <= 0) errs.price = "Enter a valid price";
    if (!form.image.trim()) errs.image = "Image URL is required";
    setErrors(errs);
    if (Object.keys(errs).length) return;
    setSubmitting(true);
    const t = toast.loading("Saving product…");
    try {
      await addProduct({
        title: form.title,
        price: form.price,
        originalPrice: form.originalPrice,
        category: form.category,
        description: form.description,
        image: form.image,
        sizes: form.sizes,
        colors: form.colors,
        stock_by_size: form.stockMap,
        // NEW additive payload fields.
        images: form.images,
        color_names: form.colorNames,
      });
      setForm({
        title: "",
        price: "",
        originalPrice: "",
        category: CATEGORIES[0],
        description: "",
        image: "",
        sizes: "",
        colors: "",
        stockMap: {},
        images: [],
        colorNames: [],
      });
      setImageDraft("");
      setColorNameDraft("");
      toast.success("Product added", { id: t, duration: 1800 });
      await reload();
    } catch (e2) {
      toast.error(`Could not save: ${e2.message}`, { id: t });
    } finally {
      setSubmitting(false);
    }
  };

  const remove = async (id) => {
    try {
      await deleteProduct(id);
      toast.success("Product removed", { duration: 1600 });
      await reload();
    } catch (e) {
      toast.error(`Delete failed: ${e.message}`);
    }
  };

  const sizesList = form.sizes
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean);

  return (
    <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 lg:gap-8 lg:h-[calc(100vh-8rem)]">
      {/* Form — its own independent scroll container on desktop */}
      <form
        onSubmit={submit}
        data-testid="admin-add-product-form"
        className="lg:col-span-2 rounded-3xl border border-white/60 bg-white/75 backdrop-blur-2xl backdrop-saturate-150 shadow-[0_12px_36px_rgba(0,0,0,0.08)] p-6 sm:p-7 space-y-4 h-fit lg:h-full lg:overflow-y-auto lg:sticky lg:top-24"
        style={{ overscrollBehavior: "contain" }}
      >
        <div>
          <p className="text-[10px] uppercase tracking-[0.22em] text-[#064E3B] font-medium mb-1">
            Add product
          </p>
          <h2 className="font-display text-2xl font-light text-[#0B0C10]">
            New listing.
          </h2>
        </div>

        <AdminField
          testId={ADMIN.titleInput}
          label="Title"
          value={form.title}
          onChange={update("title")}
          error={errors.title}
          placeholder="Silk Saree, Festive Edit"
        />
        <AdminField
          testId={ADMIN.priceInput}
          label="Selling Price (Final Price) (₹)"
          value={form.price}
          onChange={update("price")}
          error={errors.price}
          placeholder="2499"
          type="number"
        />
        <AdminField
          testId="admin-original-price-input"
          label="Original Price (Before Discount) (₹)"
          value={form.originalPrice}
          onChange={update("originalPrice")}
          placeholder="3999 (optional)"
          type="number"
        />
        <label className="block">
          <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5">
            Category
          </span>
          <select
            data-testid={ADMIN.categorySelect}
            value={form.category}
            onChange={update("category")}
            className="w-full bg-white/70 border border-white/60 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-2xl px-4 py-3 text-sm appearance-none"
          >
            {CATEGORIES.map((c) => (
              <option key={c} value={c}>
                {c}
              </option>
            ))}
          </select>
        </label>
        <AdminField
          testId={ADMIN.descriptionInput}
          label="Description"
          value={form.description}
          onChange={update("description")}
          placeholder="Short, punchy copy that sells."
          textarea
        />
        <AdminField
          testId="admin-sizes-input"
          label="Sizes (comma separated)"
          value={form.sizes}
          onChange={update("sizes")}
          placeholder="S, M, L, XL, XXL — leave blank for Free Size"
        />
        {sizesList.length > 0 && (
          <div
            className="rounded-2xl border border-[#E0B53C]/30 bg-white/70 p-4 space-y-2"
            data-testid="admin-stock-grid"
          >
            <div className="flex items-center gap-2">
              <Box size={14} strokeWidth={1.8} className="text-[#064E3B]" />
              <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
                Initial stock per size
              </span>
            </div>
            <div className="grid grid-cols-3 sm:grid-cols-5 gap-2">
              {sizesList.map((s) => (
                <label key={s} className="block">
                  <span className="block text-[10px] uppercase tracking-[0.18em] text-neutral-500 mb-1">
                    {s}
                  </span>
                  <input
                    type="number"
                    min={0}
                    value={form.stockMap[s] ?? 0}
                    onChange={(e) =>
                      setForm((p) => ({
                        ...p,
                        stockMap: { ...p.stockMap, [s]: e.target.value },
                      }))
                    }
                    data-testid={`admin-stock-input-${s.replace(/\s+/g, "-")}`}
                    className="w-full bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-2 py-2 text-sm text-center transition-all"
                  />
                </label>
              ))}
            </div>
            <p className="text-[10px] text-neutral-500">
              Leave any size at 0 to mark it as out-of-stock at launch.
            </p>
          </div>
        )}
        <AdminField
          testId="admin-colors-input"
          label="Product Colors (up to 6 comma-separated image URLs)"
          value={form.colors}
          onChange={update("colors")}
          placeholder="https://...red.jpg, https://...blue.jpg, ..."
          textarea
        />
        <AdminField
          testId={ADMIN.imageInput}
          label="Image URL"
          value={form.image}
          onChange={update("image")}
          error={errors.image}
          placeholder="https://..."
        />

        {/* NEW additive: direct device file upload for the main image.
            Click → native file picker (camera/gallery on mobile, file
            picker on PC) → uploads to backend → URL auto-fills above. */}
        <div data-testid="admin-main-upload-row">
          <input
            ref={mainFileRef}
            type="file"
            accept="image/*"
            onChange={handleMainFile}
            data-testid="admin-main-file-input"
            className="hidden"
          />
          <button
            type="button"
            data-testid="admin-main-upload-btn"
            onClick={() => mainFileRef.current?.click()}
            disabled={mainUploading}
            className="w-full inline-flex items-center justify-center gap-2 bg-[#022C22] text-[#E0B53C] rounded-2xl py-3 text-sm font-medium hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
          >
            {mainUploading ? (
              <>
                <Loader2 size={16} strokeWidth={1.8} className="animate-spin" />
                Uploading…
              </>
            ) : (
              <>
                <Upload size={16} strokeWidth={1.8} />
                Upload from device
              </>
            )}
          </button>
          <p className="text-[10px] text-neutral-500 mt-1.5 text-center">
            Choose a photo from your phone, camera, or PC — no URL needed.
          </p>
        </div>

        <ImageCropper
          sourceValue={form.image}
          onCommit={async (value) => {
            setForm((p) => ({ ...p, image: value }));
            const t = toast.loading("Enhancing image with AI…");
            try {
              const result = await enhanceImage(value);
              setForm((p) => ({ ...p, image: result.dataUrl }));
              toast.success("AI enhancement applied", {
                id: t,
                description: `Sharpen · Contrast · Colour · ${result.width}×${result.height} · ${result.sizeKb} KB`,
                duration: 2600,
              });
            } catch {
              // Silently fall back to saving the original cropped image.
              toast.dismiss(t);
            }
          }}
        />

        {form.image && (
          <div className="rounded-2xl overflow-hidden border border-white/60 bg-white/40 aspect-[4/3] relative">
            <LazyImage
              src={form.image}
              alt="preview"
              wrapperClassName="w-full h-full"
              className="absolute inset-0 w-full h-full object-cover"
            />
          </div>
        )}

        {/* ────────────────────────────────────────────────────────────
            NEW additive section: Additional product images (gallery).
            Lets the admin attach multiple supplementary image URLs to a
            product. Each row can be removed independently. Pasting a URL
            and pressing Enter or "Add image" appends it to `form.images`.
            ──────────────────────────────────────────────────────────── */}
        <div
          className="rounded-2xl border border-[#E0B53C]/30 bg-white/70 p-4 space-y-3"
          data-testid="admin-gallery-section"
        >
          <div className="flex items-center gap-2">
            <ImagePlus
              size={14}
              strokeWidth={1.8}
              className="text-[#064E3B]"
            />
            <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
              Additional images · {form.images.length}
            </span>
          </div>
          <div className="flex gap-2">
            <input
              data-testid="admin-gallery-input"
              type="url"
              value={imageDraft}
              onChange={(e) => setImageDraft(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === "Enter") {
                  e.preventDefault();
                  const v = imageDraft.trim();
                  if (v) {
                    setForm((p) => ({ ...p, images: [...p.images, v] }));
                    setImageDraft("");
                  }
                }
              }}
              placeholder="https://…  (press Enter or tap Add)"
              className="flex-1 bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2.5 text-sm transition-all"
            />
            <button
              type="button"
              data-testid="admin-gallery-add-btn"
              onClick={() => {
                const v = imageDraft.trim();
                if (!v) return;
                setForm((p) => ({ ...p, images: [...p.images, v] }));
                setImageDraft("");
              }}
              className="inline-flex items-center gap-1.5 bg-[#0B0C10] text-white rounded-xl px-3 py-2.5 text-xs font-medium hover:-translate-y-0.5 transition-all"
            >
              <Plus size={14} strokeWidth={2} />
              Add image
            </button>
          </div>

          {/* NEW additive: direct device upload for one or many gallery files.
              Hidden input + visible button. Each picked file is uploaded to
              the backend and its URL pushed into `form.images`. */}
          <input
            ref={galleryFileRef}
            type="file"
            accept="image/*"
            multiple
            onChange={handleGalleryFiles}
            data-testid="admin-gallery-file-input"
            className="hidden"
          />
          <button
            type="button"
            data-testid="admin-gallery-upload-btn"
            onClick={() => galleryFileRef.current?.click()}
            disabled={galleryUploading}
            className="w-full inline-flex items-center justify-center gap-2 bg-[#022C22] text-[#E0B53C] rounded-xl py-2.5 text-xs font-medium hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
          >
            {galleryUploading ? (
              <>
                <Loader2 size={14} strokeWidth={1.8} className="animate-spin" />
                Uploading…
              </>
            ) : (
              <>
                <Upload size={14} strokeWidth={1.8} />
                Upload from device (multiple)
              </>
            )}
          </button>
          {form.images.length > 0 && (
            <div
              className="grid grid-cols-3 sm:grid-cols-4 gap-2"
              data-testid="admin-gallery-list"
            >
              {form.images.map((url, idx) => (
                <div
                  key={`${url}-${idx}`}
                  className="relative aspect-square rounded-xl overflow-hidden border border-black/10 bg-white/70 group"
                  data-testid={`admin-gallery-item-${idx}`}
                >
                  <LazyImage
                    src={url}
                    alt={`extra ${idx + 1}`}
                    wrapperClassName="w-full h-full"
                    className="absolute inset-0 w-full h-full object-cover"
                  />
                  <button
                    type="button"
                    aria-label="remove image"
                    data-testid={`admin-gallery-remove-${idx}`}
                    onClick={() =>
                      setForm((p) => ({
                        ...p,
                        images: p.images.filter((_, i) => i !== idx),
                      }))
                    }
                    className="absolute top-1 right-1 w-6 h-6 rounded-full bg-white/95 text-red-600 flex items-center justify-center shadow opacity-0 group-hover:opacity-100 transition-opacity"
                  >
                    <Trash2 size={12} strokeWidth={2} />
                  </button>
                </div>
              ))}
            </div>
          )}
          <p className="text-[10px] text-neutral-500">
            These appear as a swipeable gallery on the product detail page.
          </p>
        </div>

        {/* ────────────────────────────────────────────────────────────
            NEW additive section: Available Colors (text tags).
            Independent from the existing image-URL "Product Colors" field.
            Type a colour name (e.g. "Royal Blue") and press Enter or comma
            to add it as a chip. Click ✕ on a chip to remove it.
            ──────────────────────────────────────────────────────────── */}
        <div
          className="rounded-2xl border border-[#E0B53C]/30 bg-white/70 p-4 space-y-3"
          data-testid="admin-color-names-section"
        >
          <div className="flex items-center gap-2">
            <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
              Available Colors · {form.colorNames.length}
            </span>
          </div>
          <div className="flex flex-wrap gap-2" data-testid="admin-color-names-list">
            {form.colorNames.map((name, idx) => (
              <span
                key={`${name}-${idx}`}
                data-testid={`admin-color-name-chip-${idx}`}
                className="inline-flex items-center gap-1.5 bg-[#0B0C10] text-white rounded-full pl-3 pr-1.5 py-1 text-xs font-medium"
              >
                {name}
                <button
                  type="button"
                  aria-label={`remove ${name}`}
                  data-testid={`admin-color-name-remove-${idx}`}
                  onClick={() =>
                    setForm((p) => ({
                      ...p,
                      colorNames: p.colorNames.filter((_, i) => i !== idx),
                    }))
                  }
                  className="w-5 h-5 rounded-full bg-white/20 hover:bg-white/35 flex items-center justify-center transition-colors"
                >
                  <Plus size={11} strokeWidth={2.5} style={{ transform: "rotate(45deg)" }} />
                </button>
              </span>
            ))}
          </div>
          <input
            data-testid="admin-color-names-input"
            type="text"
            value={colorNameDraft}
            onChange={(e) => {
              const v = e.target.value;
              // Comma also commits — supports paste "Red, Blue, Forest".
              if (v.includes(",")) {
                const parts = v.split(",").map((s) => s.trim()).filter(Boolean);
                if (parts.length) {
                  setForm((p) => ({
                    ...p,
                    colorNames: Array.from(
                      new Set([...p.colorNames, ...parts]),
                    ).slice(0, 12),
                  }));
                }
                setColorNameDraft("");
              } else {
                setColorNameDraft(v);
              }
            }}
            onKeyDown={(e) => {
              if (e.key === "Enter") {
                e.preventDefault();
                const v = colorNameDraft.trim();
                if (!v) return;
                setForm((p) => ({
                  ...p,
                  colorNames: Array.from(
                    new Set([...p.colorNames, v]),
                  ).slice(0, 12),
                }));
                setColorNameDraft("");
              }
              if (e.key === "Backspace" && !colorNameDraft && form.colorNames.length) {
                setForm((p) => ({
                  ...p,
                  colorNames: p.colorNames.slice(0, -1),
                }));
              }
            }}
            placeholder="Type a colour and press Enter (e.g. Royal Blue, Maroon)"
            className="w-full bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2.5 text-sm transition-all"
          />
          <p className="text-[10px] text-neutral-500">
            Up to 12 colours. Customers see these as selectable text chips on
            the product page.
          </p>
        </div>

        <button
          type="submit"
          disabled={submitting}
          data-testid={ADMIN.addProductBtn}
          className="w-full inline-flex items-center justify-center gap-2 bg-[#0B0C10] text-white rounded-full py-3.5 font-medium tracking-wide hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
        >
          <Plus size={16} strokeWidth={1.8} />
          {submitting ? "Saving…" : "Add to storefront"}
        </button>
      </form>

      {/* Product list */}
      <div
        data-testid="admin-product-catalog-list"
        className="lg:col-span-3 space-y-3 lg:h-full lg:overflow-y-auto lg:pr-2"
        style={{ overscrollBehavior: "contain" }}
      >
        {products.length > 0 && (
          <BulkVisibilityBar
            products={products}
            categories={Array.from(new Set(products.map((p) => p.category).filter(Boolean)))}
            onChanged={reload}
          />
        )}
        {products.length === 0 ? (
          <div className="rounded-3xl border border-white/60 bg-white/60 backdrop-blur-xl p-10 text-center">
            <ImageIcon
              size={28}
              strokeWidth={1.5}
              className="mx-auto mb-4 text-neutral-400"
            />
            <p className="font-display text-xl text-[#0B0C10] mb-1">
              No products yet.
            </p>
            <p className="text-sm text-neutral-600">
              Use the form to add your first listing.
            </p>
          </div>
        ) : (
          products.map((p) => {
            const stock = p.stock_by_size || {};
            const totalStock = Object.values(stock).reduce(
              (a, b) => a + (Number(b) || 0),
              0,
            );
            const vState = computeVisibilityState(p);
            const vLabel = visibilityStateLabel(vState);
            const vHint = visibilityHint(p, vState);
            const dimmed = vState === "hidden" || vState === "expired";
            return (
              <div
                key={p.id}
                data-testid={ADMIN.productRow(p.id)}
                className={`flex items-center gap-4 rounded-2xl border border-white/60 bg-white/70 backdrop-blur-xl p-3 sm:p-4 shadow-[0_6px_20px_rgba(0,0,0,0.05)] transition-opacity ${dimmed ? "opacity-60" : ""}`}
              >
                <div className="w-16 h-16 sm:w-20 sm:h-20 rounded-xl overflow-hidden bg-white shrink-0 relative">
                  <LazyImage
                    src={p.image}
                    alt={p.title}
                    wrapperClassName="w-full h-full"
                    className="absolute inset-0 w-full h-full object-cover"
                  />
                </div>
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <p className="text-[10px] uppercase tracking-[0.22em] text-[#064E3B] font-medium truncate">
                      {p.category}
                    </p>
                    <span
                      data-testid={`admin-product-visibility-state-${p.id}`}
                      data-state={vState}
                      className={`text-[9px] uppercase tracking-[0.18em] font-semibold px-1.5 py-0.5 rounded-full ${
                        vState === "hidden"
                          ? "bg-neutral-200 text-neutral-600"
                          : vState === "scheduled"
                            ? "bg-[#FFF9E6] text-[#8a6b00]"
                            : vState === "expired"
                              ? "bg-red-50 text-red-600"
                              : "bg-[#D1FFEB] text-[#064E3B]"
                      }`}
                    >
                      {vLabel}
                    </span>
                  </div>
                  <h3 className="font-display text-base sm:text-lg truncate text-[#0B0C10]">
                    {p.title}
                  </h3>
                  <p className="text-sm text-neutral-600">{formatINR(p.price)}</p>
                  <ProductQuickEdit product={p} onSaved={reload} />
                  {vHint && (
                    <p
                      data-testid={`admin-product-schedule-hint-${p.id}`}
                      className="text-[10px] uppercase tracking-[0.18em] text-[#064E3B] mt-0.5 truncate"
                    >
                      🕒 {vHint}
                    </p>
                  )}
                  {Array.isArray(p.sizes) && p.sizes.length > 0 && (
                    <p
                      className="text-[10px] uppercase tracking-[0.18em] text-neutral-500 mt-1 truncate"
                      data-testid={`admin-product-sizes-${p.id}`}
                    >
                      Sizes · {p.sizes.join(" · ")}
                    </p>
                  )}
                  {Array.isArray(p.sizes) && p.sizes.length > 0 && (
                    <p
                      className={`text-[10px] uppercase tracking-[0.18em] mt-1 ${
                        totalStock === 0 ? "text-red-500" : "text-[#064E3B]"
                      }`}
                      data-testid={`admin-product-stock-${p.id}`}
                    >
                      Stock · {totalStock} unit{totalStock === 1 ? "" : "s"}
                    </p>
                  )}
                </div>
                <div className="flex items-center gap-1.5">
                  <VisibilityToggle product={p} onChanged={reload} />
                  <button
                    onClick={() => setScheduleFor(p)}
                    data-testid={`admin-schedule-btn-${p.id}`}
                    className={`p-2.5 rounded-full transition-colors ${
                      p.active_from || p.active_until
                        ? "bg-[#FFF9E6] text-[#022C22] hover:bg-[#FFE9A6]"
                        : "bg-white/80 hover:bg-[#FFF9E6] text-neutral-600 hover:text-[#022C22]"
                    }`}
                    aria-label="schedule visibility"
                    title="Schedule visibility"
                  >
                    <Calendar size={16} strokeWidth={1.6} />
                  </button>
                  {Array.isArray(p.sizes) && p.sizes.length > 0 && (
                    <button
                      onClick={() => setStockEditFor(p)}
                      data-testid={`admin-edit-stock-${p.id}`}
                      className="p-2.5 rounded-full bg-white/80 hover:bg-[#FFF9E6] text-neutral-600 hover:text-[#022C22] transition-colors"
                      aria-label="edit stock"
                      title="Edit stock"
                    >
                      <Box size={16} strokeWidth={1.6} />
                    </button>
                  )}
                  <button
                    onClick={() => remove(p.id)}
                    data-testid={ADMIN.deleteProductBtn(p.id)}
                    className="p-2.5 rounded-full bg-white/80 hover:bg-red-50 text-neutral-600 hover:text-red-600 transition-colors"
                    aria-label="delete"
                  >
                    <Trash2 size={16} strokeWidth={1.6} />
                  </button>
                </div>
              </div>
            );
          })
        )}
      </div>

      {stockEditFor && (
        <StockGrid
          product={stockEditFor}
          onClose={() => setStockEditFor(null)}
          onSaved={() => reload()}
        />
      )}
      {scheduleFor && (
        <ScheduleModal
          product={scheduleFor}
          onClose={() => setScheduleFor(null)}
          onSaved={() => reload()}
        />
      )}
    </div>
  );
};

const OrdersTab = ({ orders, reload }) => {
  const [pendingDelete, setPendingDelete] = useState(null);
  const [deleting, setDeleting] = useState(false);

  const confirmDelete = async () => {
    if (!pendingDelete) return;
    setDeleting(true);
    const t = toast.loading("Deleting order…");
    try {
      await apiDeleteOrder(pendingDelete.id);
      toast.success("Order deleted", { id: t, duration: 1600 });
      setPendingDelete(null);
      await reload();
    } catch (err) {
      toast.error(err?.message || "Failed to delete", { id: t });
    } finally {
      setDeleting(false);
    }
  };

  if (orders.length === 0) {
    return (
      <div className="rounded-3xl border border-white/60 bg-white/60 backdrop-blur-xl p-10 text-center">
        <ShoppingBag
          size={28}
          strokeWidth={1.5}
          className="mx-auto mb-4 text-neutral-400"
        />
        <p className="font-display text-xl text-[#0B0C10] mb-1">No orders yet.</p>
        <p className="text-sm text-neutral-600">
          Orders placed via the storefront will appear here.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-3">
      {orders.map((o) => (
        <div
          key={o.id}
          data-testid={ADMIN.orderRow(o.id)}
          className="rounded-2xl border border-white/60 bg-white/75 backdrop-blur-xl p-4 sm:p-5 shadow-[0_6px_20px_rgba(0,0,0,0.05)] space-y-4"
        >
          <div className="flex flex-col sm:flex-row sm:items-start gap-4">
            <div className="w-16 h-16 rounded-xl overflow-hidden bg-white shrink-0 relative">
              <LazyImage
                src={o.productImage}
                alt={o.productTitle}
                wrapperClassName="w-full h-full"
                className="absolute inset-0 w-full h-full object-cover"
              />
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-baseline gap-2 flex-wrap">
                <p className="font-mono text-[11px] text-neutral-500">
                  #{o.id}
                </p>
                <span
                  data-testid={`admin-order-payment-${o.id}`}
                  className="text-[10px] uppercase tracking-[0.18em] text-neutral-500"
                >
                  {o.payment}
                </span>
              </div>
              <h3 className="font-display text-base sm:text-lg text-[#0B0C10] truncate">
                {o.productTitle}
              </h3>
              {Array.isArray(o.items) && o.items.length > 0 && (
                <ul
                  className="mt-2 mb-1 space-y-2"
                  data-testid={`admin-order-items-${o.id}`}
                >
                  {o.items.map((it, idx) => (
                    <li
                      key={idx}
                      className="flex items-start gap-2.5 rounded-xl bg-white/70 border border-black/5 p-2"
                      data-testid={`admin-order-item-${o.id}-${idx}`}
                    >
                      <div
                        className="w-14 h-14 rounded-lg overflow-hidden bg-white shrink-0 border border-black/10 relative"
                        data-testid={`admin-order-item-image-${o.id}-${idx}`}
                      >
                        <LazyImage
                          src={it.image || o.productImage}
                          alt={it.title || o.productTitle}
                          wrapperClassName="w-full h-full"
                          className="absolute inset-0 w-full h-full object-cover"
                        />
                      </div>
                      <div className="flex-1 min-w-0">
                        <p
                          className="text-sm font-medium text-[#0B0C10] truncate"
                          data-testid={`admin-order-item-title-${o.id}-${idx}`}
                        >
                          {it.title || o.productTitle}
                        </p>
                        {it.productId && (
                          <p
                            className="font-mono text-[10px] text-neutral-500 truncate"
                            data-testid={`admin-order-item-pid-${o.id}-${idx}`}
                          >
                            #{it.productId}
                          </p>
                        )}
                        <div className="flex items-center gap-1.5 mt-0.5 flex-wrap">
                          {it.color && (
                            <img
                              src={it.color}
                              alt={it.colorLabel || "color"}
                              className="w-3.5 h-3.5 rounded-full object-cover ring-1 ring-black/10 shrink-0"
                              loading="lazy"
                            />
                          )}
                          <span className="text-[11px] font-semibold text-[#064E3B]">
                            Size {it.size || "Free Size"}
                            {it.colorLabel && <> · {it.colorLabel}</>}
                          </span>
                          <span className="text-[11px] text-neutral-600">× {it.qty}</span>
                          {it.price !== undefined && (
                            <span className="text-[11px] text-neutral-500">
                              @ {formatINR(it.price)}
                            </span>
                          )}
                        </div>
                      </div>
                    </li>
                  ))}
                </ul>
              )}
              <p
                className="text-sm text-neutral-700"
                data-testid={`admin-order-contact-${o.id}`}
              >
                {o.name} · {o.phone}
                {o.customer_email && (
                  <>
                    <span className="mx-1 text-neutral-400">·</span>
                    <span className="text-[#064E3B] font-medium">
                      {o.customer_email}
                    </span>
                  </>
                )}
              </p>
              <p className="text-sm text-neutral-600 line-clamp-2">
                {o.address} — {o.pincode}
              </p>
            </div>
            <div className="sm:text-right shrink-0">
              <p className="font-display text-xl text-[#0B0C10]">
                {formatINR(o.price)}
              </p>
              <p className="text-[11px] text-neutral-500">
                {new Date(o.createdAt).toLocaleString("en-IN", {
                  dateStyle: "medium",
                  timeStyle: "short",
                })}
              </p>
              <button
                type="button"
                onClick={() => setPendingDelete(o)}
                data-testid={`admin-order-delete-${o.id}`}
                aria-label="Delete order"
                className="mt-2 inline-flex items-center gap-1.5 text-[11px] font-medium text-red-600 hover:text-white hover:bg-red-600 border border-red-200 hover:border-red-600 rounded-full px-3 py-1 transition-colors"
              >
                <Trash2 size={12} strokeWidth={1.8} />
                Delete
              </button>
            </div>
          </div>
          <OrderStatusStepper order={o} onUpdated={() => reload?.()} />
        </div>
      ))}

      <AlertDialog
        open={!!pendingDelete}
        onOpenChange={(open) => !open && !deleting && setPendingDelete(null)}
      >
        <AlertDialogContent data-testid="admin-order-delete-dialog">
          <AlertDialogHeader>
            <AlertDialogTitle>Delete this order?</AlertDialogTitle>
            <AlertDialogDescription>
              Are you sure you want to delete this order?
              {pendingDelete && (
                <span className="block mt-2 text-xs text-neutral-500">
                  Order <span className="font-mono">#{pendingDelete.id}</span> ·{" "}
                  {pendingDelete.name} · {pendingDelete.phone}
                </span>
              )}
              <span className="block mt-2 text-xs text-red-600">
                This permanently removes the order and all associated customer
                details. This action cannot be undone.
              </span>
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel
              data-testid="admin-order-delete-cancel"
              disabled={deleting}
            >
              Cancel
            </AlertDialogCancel>
            <AlertDialogAction
              data-testid="admin-order-delete-confirm"
              onClick={(e) => {
                e.preventDefault();
                confirmDelete();
              }}
              disabled={deleting}
              className="bg-red-600 hover:bg-red-700 focus:ring-red-600"
            >
              {deleting ? "Deleting…" : "Delete permanently"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
};

const AdminField = ({
  label,
  value,
  onChange,
  placeholder,
  error,
  testId,
  textarea,
  type = "text",
}) => {
  const Comp = textarea ? "textarea" : "input";
  return (
    <label className="block">
      <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5">
        {label}
      </span>
      <Comp
        data-testid={testId}
        type={textarea ? undefined : type}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        rows={textarea ? 3 : undefined}
        className={`w-full bg-white/70 border ${error ? "border-red-400" : "border-white/60"} focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-2xl px-4 py-3 text-sm transition-all`}
      />
      {error && (
        <span className="block text-[11px] text-red-500 mt-1">{error}</span>
      )}
    </label>
  );
};

// Per-row visibility toggle for the admin product list. Flips `is_active` via
// PATCH /api/products/{id}/visibility and triggers a parent reload so the
// "Live / Hidden" pill, faded row state, and storefront stay in sync.
const VisibilityToggle = ({ product, onChanged }) => {
  const [busy, setBusy] = useState(false);
  const isActive = product.is_active !== false;

  const flip = async () => {
    if (busy) return;
    setBusy(true);
    const t = toast.loading(isActive ? "Hiding product…" : "Publishing product…");
    try {
      const updated = await apiUpdateVisibility(product.id, !isActive);
      toast.success(
        updated.is_active === false
          ? "Hidden from storefront"
          : "Now live on storefront",
        { id: t, duration: 1800 },
      );
      onChanged?.();
    } catch (e) {
      toast.error(e?.message || "Could not update visibility", { id: t });
    } finally {
      setBusy(false);
    }
  };

  return (
    <button
      type="button"
      onClick={flip}
      disabled={busy}
      role="switch"
      aria-checked={isActive}
      aria-label={isActive ? "Hide product" : "Publish product"}
      title={isActive ? "Hide from storefront" : "Publish to storefront"}
      data-testid={`admin-visibility-toggle-${product.id}`}
      data-state={isActive ? "active" : "inactive"}
      className={`relative inline-flex items-center w-11 h-6 rounded-full transition-colors ${
        isActive ? "bg-[#022C22]" : "bg-neutral-300"
      } disabled:opacity-60`}
    >
      <span
        className={`absolute inline-flex items-center justify-center w-5 h-5 rounded-full bg-white shadow transform transition-transform ${
          isActive ? "translate-x-5" : "translate-x-0.5"
        }`}
      >
        {busy ? (
          <Loader2 size={10} strokeWidth={2.2} className="animate-spin text-[#022C22]" />
        ) : isActive ? (
          <Eye size={10} strokeWidth={2.2} className="text-[#022C22]" />
        ) : (
          <EyeOff size={10} strokeWidth={2.2} className="text-neutral-500" />
        )}
      </span>
    </button>
  );
};
