import React, { useEffect, useMemo, useRef, useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import {
  Crop,
  Upload,
  Link as LinkIcon,
  RotateCcw,
  Check,
  X,
  Scissors,
  ShieldCheck,
} from "lucide-react";
import { toast } from "sonner";

const clamp = (n, min, max) => Math.max(min, Math.min(max, n));

const BACKEND = process.env.REACT_APP_BACKEND_URL;

// Universal CORS bypass — any external http(s) URL is routed through our
// backend proxy so the browser treats the image as same-origin and the
// canvas can read its pixels (needed for cropping + AI enhancement).
// dataURL / blob / already-backend sources pass through untouched.
const toCanvasSafeSrc = (src) => {
  if (!src) return "";
  if (typeof src !== "string") return src;
  if (src.startsWith("data:") || src.startsWith("blob:")) return src;
  if (!BACKEND) return src; // mis-config: bail out instead of building bad URL
  if (src.startsWith(BACKEND)) return src;
  if (src.startsWith("/api/")) return `${BACKEND}${src}`;
  if (src.startsWith("http://") || src.startsWith("https://")) {
    return `${BACKEND}/api/proxy-image?url=${encodeURIComponent(src)}`;
  }
  return src;
};

// Quick framing presets — operate on the normalised (0..1) crop rect.
// "Top 93%" crops off the bottom 7% (the user's original framing intent).
const PRESETS = [
  { id: "full", label: "Full", rect: { x: 0, y: 0, w: 1, h: 1 } },
  { id: "top93", label: "Top 93%", rect: { x: 0, y: 0, w: 1, h: 0.93 } },
  { id: "square", label: "Square 1:1", rect: { x: 0, y: 0, w: 1, h: 1, aspect: 1 } },
  { id: "portrait", label: "Portrait 4:5", rect: { x: 0, y: 0, w: 1, h: 1, aspect: 4 / 5 } },
];

// Compute a rect that fits an aspect ratio inside the image (centered).
const fitAspect = (aspect, imgNaturalRatio) => {
  if (aspect >= imgNaturalRatio) {
    const w = 1;
    const h = imgNaturalRatio / aspect;
    return { x: 0, y: (1 - h) / 2, w, h };
  } else {
    const h = 1;
    const w = aspect / imgNaturalRatio;
    return { x: (1 - w) / 2, y: 0, w, h };
  }
};

export const ImageCropper = ({ sourceValue, onCommit }) => {
  const [mode, setMode] = useState("url"); // "url" or "upload"
  const [source, setSource] = useState(sourceValue || "");
  const [imgReady, setImgReady] = useState(false);
  const [naturalSize, setNaturalSize] = useState({ w: 1, h: 1 });
  const [rect, setRect] = useState({ x: 0, y: 0, w: 1, h: 1 });
  const [busy, setBusy] = useState(false);
  const containerRef = useRef(null);
  const imgRef = useRef(null);

  // The URL we hand the <img> tag and the canvas. For external URLs this is
  // the backend proxy URL; for dataURLs / uploads it's the source itself.
  const displaySource = useMemo(() => toCanvasSafeSrc(source), [source]);
  const isProxied =
    typeof source === "string" &&
    (source.startsWith("http://") || source.startsWith("https://")) &&
    !(BACKEND && source.startsWith(BACKEND));

  // Reset rect when source changes.
  useEffect(() => {
    setImgReady(false);
    setRect({ x: 0, y: 0, w: 1, h: 1 });
  }, [source]);

  const handleUrlChange = (e) => {
    setSource(e.target.value);
  };

  const handleFile = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      toast.error("Please choose an image file");
      return;
    }
    // Refuse files > 20MB to mirror the backend proxy ceiling.
    if (file.size > 20 * 1024 * 1024) {
      toast.error("Image too large (20MB max). Try a smaller one.");
      return;
    }
    const reader = new FileReader();
    reader.onload = () => {
      setSource(reader.result);
      toast.success(`Loaded ${file.name}`, { duration: 1400 });
    };
    reader.onerror = () => {
      toast.error("Couldn't read this file");
    };
    reader.readAsDataURL(file);
  };

  const handleImgLoad = (e) => {
    const el = e.currentTarget;
    setNaturalSize({ w: el.naturalWidth, h: el.naturalHeight });
    setImgReady(true);
  };

  const handleImgError = () => {
    setImgReady(false);
  };

  const applyPreset = (preset) => {
    if (!imgReady) return;
    if (preset.rect.aspect) {
      const ratio = naturalSize.w / naturalSize.h;
      const fitted = fitAspect(preset.rect.aspect, ratio);
      setRect(fitted);
    } else {
      const { aspect: _ignore, ...rest } = preset.rect;
      setRect(rest);
    }
  };

  // Pointer drag — supports "move" and four corners.
  const dragRef = useRef(null);
  const onPointerDown = (handle) => (e) => {
    e.preventDefault();
    e.stopPropagation();
    const ctn = containerRef.current?.getBoundingClientRect();
    if (!ctn) return;
    dragRef.current = {
      handle,
      startX: e.clientX,
      startY: e.clientY,
      ctnW: ctn.width,
      ctnH: ctn.height,
      r0: { ...rect },
    };
    try {
      e.currentTarget.setPointerCapture(e.pointerId);
    } catch {
      /* noop */
    }
    document.addEventListener("pointermove", onPointerMove);
    document.addEventListener("pointerup", onPointerUp);
  };

  const onPointerMove = (e) => {
    const s = dragRef.current;
    if (!s) return;
    const dxN = (e.clientX - s.startX) / s.ctnW;
    const dyN = (e.clientY - s.startY) / s.ctnH;
    let r = { ...s.r0 };
    const MIN = 0.08;
    switch (s.handle) {
      case "move":
        r.x = clamp(s.r0.x + dxN, 0, 1 - s.r0.w);
        r.y = clamp(s.r0.y + dyN, 0, 1 - s.r0.h);
        break;
      case "se":
        r.w = clamp(s.r0.w + dxN, MIN, 1 - s.r0.x);
        r.h = clamp(s.r0.h + dyN, MIN, 1 - s.r0.y);
        break;
      case "sw": {
        const newX = clamp(s.r0.x + dxN, 0, s.r0.x + s.r0.w - MIN);
        r.w = s.r0.w - (newX - s.r0.x);
        r.h = clamp(s.r0.h + dyN, MIN, 1 - s.r0.y);
        r.x = newX;
        break;
      }
      case "ne": {
        const newY = clamp(s.r0.y + dyN, 0, s.r0.y + s.r0.h - MIN);
        r.w = clamp(s.r0.w + dxN, MIN, 1 - s.r0.x);
        r.h = s.r0.h - (newY - s.r0.y);
        r.y = newY;
        break;
      }
      case "nw": {
        const newX = clamp(s.r0.x + dxN, 0, s.r0.x + s.r0.w - MIN);
        const newY = clamp(s.r0.y + dyN, 0, s.r0.y + s.r0.h - MIN);
        r.w = s.r0.w - (newX - s.r0.x);
        r.h = s.r0.h - (newY - s.r0.y);
        r.x = newX;
        r.y = newY;
        break;
      }
      default:
        break;
    }
    setRect(r);
  };

  const onPointerUp = () => {
    dragRef.current = null;
    document.removeEventListener("pointermove", onPointerMove);
    document.removeEventListener("pointerup", onPointerUp);
  };

  const applyCrop = async () => {
    if (!imgReady) {
      toast.error("Load an image first");
      return;
    }
    setBusy(true);
    try {
      const img = new window.Image();
      img.crossOrigin = "anonymous";
      const loaded = new Promise((resolve, reject) => {
        img.onload = () => resolve();
        img.onerror = () => reject(new Error("image load failed"));
      });
      // Always load through the canvas-safe (proxy-aware) URL.
      img.src = displaySource;
      await loaded;

      const sx = Math.round(rect.x * img.naturalWidth);
      const sy = Math.round(rect.y * img.naturalHeight);
      const sw = Math.max(1, Math.round(rect.w * img.naturalWidth));
      const sh = Math.max(1, Math.round(rect.h * img.naturalHeight));

      const canvas = document.createElement("canvas");
      canvas.width = sw;
      canvas.height = sh;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(img, sx, sy, sw, sh, 0, 0, sw, sh);

      const dataUrl = canvas.toDataURL("image/jpeg", 0.88);
      onCommit(dataUrl);
      toast.success("Cropped image saved", {
        description: `${sw}×${sh}px ready to upload`,
        duration: 2200,
      });
    } catch (err) {
      const isLoadErr = String(err?.message || "")
        .toLowerCase()
        .includes("load");
      toast.error(
        isLoadErr
          ? "Couldn't fetch this image. The source may be offline or blocked even via our proxy."
          : "Crop failed. Try a different image.",
        { duration: 3000 },
      );
    } finally {
      setBusy(false);
    }
  };

  const useFullImage = () => {
    if (!source) {
      toast.error("Add an image first");
      return;
    }
    onCommit(source);
    toast.success("Image saved without cropping", { duration: 1800 });
  };

  return (
    <div
      data-testid="admin-image-cropper"
      className="rounded-2xl border border-[#E0B53C]/30 bg-white/70 p-4 space-y-3"
    >
      <div className="flex items-center gap-2">
        <Scissors size={14} strokeWidth={1.8} className="text-[#064E3B]" />
        <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
          Manual Image Cropper
        </span>
      </div>

      {/* Source selector */}
      <div className="flex items-center gap-2 flex-wrap">
        <ModeBtn
          active={mode === "url"}
          onClick={() => setMode("url")}
          icon={<LinkIcon size={13} strokeWidth={1.8} />}
          label="URL"
          testId="cropper-mode-url"
        />
        <ModeBtn
          active={mode === "upload"}
          onClick={() => setMode("upload")}
          icon={<Upload size={13} strokeWidth={1.8} />}
          label="Upload"
          testId="cropper-mode-upload"
        />
      </div>

      {mode === "url" ? (
        <div className="space-y-1.5">
          <input
            type="text"
            value={typeof source === "string" && !source.startsWith("data:") ? source : ""}
            onChange={handleUrlChange}
            placeholder="https://… any product image URL"
            data-testid="cropper-url-input"
            className="w-full bg-white/80 border border-white/60 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2 text-sm transition-all"
          />
          {isProxied && (
            <p
              className="flex items-center gap-1 text-[10px] uppercase tracking-[0.18em] text-[#064E3B] font-medium"
              data-testid="cropper-proxy-badge"
            >
              <ShieldCheck size={11} strokeWidth={2} />
              CORS bypass active · routed through MastiBazaar proxy
            </p>
          )}
        </div>
      ) : (
        <input
          type="file"
          accept="image/*"
          onChange={handleFile}
          data-testid="cropper-file-input"
          className="block w-full text-xs text-neutral-700 file:mr-3 file:py-2 file:px-3 file:rounded-full file:border-0 file:text-xs file:font-medium file:bg-[#022C22] file:text-[#E0B53C] hover:file:bg-[#053f30] cursor-pointer"
        />
      )}

      {/* Preview + crop overlay */}
      {source ? (
        <div
          ref={containerRef}
          className="relative rounded-xl overflow-hidden bg-neutral-900/95 select-none touch-none aspect-[4/3] w-full"
          data-testid="cropper-preview"
        >
          <img
            ref={imgRef}
            src={displaySource}
            crossOrigin="anonymous"
            alt="source"
            onLoad={handleImgLoad}
            onError={handleImgError}
            className="absolute inset-0 w-full h-full object-contain"
          />
          {imgReady && (
            <>
              {/* Dim overlay outside crop rect */}
              <div
                aria-hidden="true"
                className="absolute inset-0 pointer-events-none"
                style={{
                  background: `linear-gradient(rgba(0,0,0,0.55), rgba(0,0,0,0.55))`,
                  clipPath: `polygon(
                    0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 0%,
                    ${rect.x * 100}% ${rect.y * 100}%,
                    ${rect.x * 100}% ${(rect.y + rect.h) * 100}%,
                    ${(rect.x + rect.w) * 100}% ${(rect.y + rect.h) * 100}%,
                    ${(rect.x + rect.w) * 100}% ${rect.y * 100}%,
                    ${rect.x * 100}% ${rect.y * 100}%
                  )`,
                }}
              />
              {/* Crop frame + handles */}
              <div
                onPointerDown={onPointerDown("move")}
                data-testid="cropper-frame"
                style={{
                  position: "absolute",
                  left: `${rect.x * 100}%`,
                  top: `${rect.y * 100}%`,
                  width: `${rect.w * 100}%`,
                  height: `${rect.h * 100}%`,
                  border: "2px solid #E0B53C",
                  boxShadow:
                    "0 0 0 1px rgba(0,0,0,0.4), 0 6px 22px rgba(224,181,60,0.35)",
                  cursor: "move",
                  touchAction: "none",
                }}
              >
                {/* Thirds grid */}
                <div className="absolute inset-0 pointer-events-none">
                  <div className="absolute left-1/3 top-0 bottom-0 border-l border-white/30" />
                  <div className="absolute left-2/3 top-0 bottom-0 border-l border-white/30" />
                  <div className="absolute top-1/3 left-0 right-0 border-t border-white/30" />
                  <div className="absolute top-2/3 left-0 right-0 border-t border-white/30" />
                </div>
                {/* Corner handles */}
                {["nw", "ne", "sw", "se"].map((corner) => (
                  <span
                    key={corner}
                    onPointerDown={onPointerDown(corner)}
                    data-testid={`cropper-handle-${corner}`}
                    style={{
                      position: "absolute",
                      width: 16,
                      height: 16,
                      background: "#E0B53C",
                      border: "2px solid white",
                      borderRadius: 9999,
                      boxShadow: "0 2px 6px rgba(0,0,0,0.4)",
                      cursor: `${corner}-resize`,
                      touchAction: "none",
                      ...(corner.includes("n") ? { top: -8 } : { bottom: -8 }),
                      ...(corner.includes("w") ? { left: -8 } : { right: -8 }),
                    }}
                  />
                ))}
              </div>
            </>
          )}
          {!imgReady && (
            <div className="absolute inset-0 flex items-center justify-center text-xs text-white/70">
              loading image…
            </div>
          )}
        </div>
      ) : (
        <div className="rounded-xl border border-dashed border-black/15 bg-white/50 p-8 text-center text-xs text-neutral-500">
          Paste an image URL or upload a file to start cropping.
        </div>
      )}

      {/* Presets */}
      {imgReady && (
        <div className="flex flex-wrap gap-2" data-testid="cropper-presets">
          {PRESETS.map((p) => (
            <button
              key={p.id}
              type="button"
              onClick={() => applyPreset(p)}
              data-testid={`cropper-preset-${p.id}`}
              className="text-[11px] uppercase tracking-[0.18em] font-medium px-3 py-1.5 rounded-full bg-white/70 border border-black/10 hover:border-[#0B0C10] transition-all"
            >
              {p.label}
            </button>
          ))}
          <div className="ml-auto text-[11px] text-neutral-500 self-center font-mono">
            {Math.round(rect.w * naturalSize.w)} × {Math.round(rect.h * naturalSize.h)} px
          </div>
        </div>
      )}

      {/* Actions */}
      <div className="flex flex-wrap items-center gap-2 pt-1">
        <button
          type="button"
          onClick={applyCrop}
          disabled={!imgReady || busy}
          data-testid="cropper-apply-btn"
          className="inline-flex items-center gap-2 bg-[#0B0C10] text-white rounded-full px-4 py-2 text-sm font-medium hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-50 disabled:cursor-not-allowed"
        >
          {busy ? (
            "Cropping…"
          ) : (
            <>
              <Crop size={14} strokeWidth={1.8} />
              Apply Crop &amp; Save
            </>
          )}
        </button>
        <button
          type="button"
          onClick={useFullImage}
          disabled={!source}
          data-testid="cropper-use-asis-btn"
          className="inline-flex items-center gap-2 bg-white/80 border border-black/10 text-[#0B0C10] rounded-full px-4 py-2 text-sm font-medium hover:bg-white transition-all disabled:opacity-50"
        >
          <Check size={14} strokeWidth={1.8} />
          Use as-is
        </button>
        <button
          type="button"
          onClick={() => setRect({ x: 0, y: 0, w: 1, h: 1 })}
          disabled={!imgReady}
          data-testid="cropper-reset-btn"
          className="inline-flex items-center gap-2 text-sm font-medium text-neutral-600 hover:text-[#0B0C10] px-3 py-2 transition-colors disabled:opacity-50"
        >
          <RotateCcw size={14} strokeWidth={1.8} />
          Reset
        </button>
      </div>
    </div>
  );
};

const ModeBtn = ({ active, onClick, icon, label, testId }) => (
  <button
    type="button"
    onClick={onClick}
    data-testid={testId}
    className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-[11px] uppercase tracking-[0.18em] font-medium border transition-all ${
      active
        ? "bg-[#022C22] text-[#E0B53C] border-[#022C22]"
        : "bg-white/70 text-[#0B0C10] border-black/10 hover:border-[#0B0C10]/40"
    }`}
  >
    {icon}
    {label}
  </button>
);
