import React, { useEffect, useMemo, useState } from "react";
import { Calendar, Clock, Save, Trash2, X } from "lucide-react";
import { toast } from "sonner";
import { apiUpdateSchedule } from "@/lib/api";

// Convert an ISO string (which may include +00:00) into the value format
// expected by <input type="datetime-local"> in the user's local timezone:
// "YYYY-MM-DDTHH:mm".
const isoToLocalInput = (iso) => {
  if (!iso) return "";
  try {
    const d = new Date(iso);
    if (Number.isNaN(d.getTime())) return "";
    const pad = (n) => String(n).padStart(2, "0");
    return `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}T${pad(d.getHours())}:${pad(d.getMinutes())}`;
  } catch {
    return "";
  }
};

// Convert the datetime-local string back to a full ISO string in UTC for
// storage. Empty input returns null.
const localInputToIso = (value) => {
  if (!value) return null;
  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return null;
  return d.toISOString();
};

const friendlyDelta = (iso, direction = "future") => {
  if (!iso) return "";
  const now = new Date();
  const then = new Date(iso);
  if (Number.isNaN(then.getTime())) return "";
  const diff = (then - now) / 1000;
  const abs = Math.abs(diff);
  const units = [
    [60 * 60 * 24 * 365, "y"],
    [60 * 60 * 24 * 30, "mo"],
    [60 * 60 * 24 * 7, "w"],
    [60 * 60 * 24, "d"],
    [60 * 60, "h"],
    [60, "min"],
  ];
  for (const [sec, label] of units) {
    if (abs >= sec) {
      const v = Math.round(abs / sec);
      return direction === "future" ? `in ${v}${label}` : `${v}${label} ago`;
    }
  }
  return "now";
};

export const ScheduleModal = ({ product, onClose, onSaved }) => {
  const [from, setFrom] = useState("");
  const [until, setUntil] = useState("");
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    setFrom(isoToLocalInput(product.active_from));
    setUntil(isoToLocalInput(product.active_until));
  }, [product]);

  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "Escape") onClose?.();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const preview = useMemo(() => {
    const f = localInputToIso(from);
    const u = localInputToIso(until);
    if (!f && !u) return "Always live (no schedule)";
    const now = new Date();
    const fd = f ? new Date(f) : null;
    const ud = u ? new Date(u) : null;
    if (fd && fd > now)
      return `Goes live ${friendlyDelta(f, "future")} · ${fd.toLocaleString("en-IN")}`;
    if (ud && ud < now) return `Expired ${friendlyDelta(u, "past")}`;
    if (ud) return `Live until ${ud.toLocaleString("en-IN")} (${friendlyDelta(u, "future")})`;
    return "Live now";
  }, [from, until]);

  const valid = useMemo(() => {
    const f = localInputToIso(from);
    const u = localInputToIso(until);
    if (f && u && new Date(u) <= new Date(f)) return false;
    return true;
  }, [from, until]);

  const save = async () => {
    if (!valid) {
      toast.error("'Hide at' must be after 'Go live at'");
      return;
    }
    setSaving(true);
    try {
      await apiUpdateSchedule(product.id, {
        activeFrom: localInputToIso(from),
        activeUntil: localInputToIso(until),
      });
      toast.success("Schedule saved", { duration: 1600 });
      onSaved?.();
      onClose?.();
    } catch (e) {
      toast.error(e?.message || "Could not save schedule");
    } finally {
      setSaving(false);
    }
  };

  const clearAll = async () => {
    setSaving(true);
    try {
      await apiUpdateSchedule(product.id, { activeFrom: null, activeUntil: null });
      toast.success("Schedule cleared", { duration: 1500 });
      onSaved?.();
      onClose?.();
    } catch (e) {
      toast.error(e?.message || "Could not clear schedule");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4"
      onClick={onClose}
      data-testid={`schedule-modal-${product.id}`}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        className="w-full max-w-md rounded-3xl bg-white shadow-2xl border border-white/60 p-6 space-y-4"
      >
        <div className="flex items-start justify-between gap-3">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Calendar size={14} strokeWidth={1.8} className="text-[#064E3B]" />
              <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
                Schedule visibility
              </span>
            </div>
            <h3 className="font-display text-xl text-[#0B0C10] line-clamp-1">
              {product.title}
            </h3>
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-full hover:bg-neutral-100"
            data-testid="schedule-modal-close"
            aria-label="close"
          >
            <X size={16} strokeWidth={1.8} />
          </button>
        </div>

        <label className="block">
          <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5 font-medium">
            Go live at (optional)
          </span>
          <input
            type="datetime-local"
            value={from}
            onChange={(e) => setFrom(e.target.value)}
            data-testid={`schedule-from-${product.id}`}
            className="w-full bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2.5 text-sm transition-all"
          />
        </label>
        <label className="block">
          <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5 font-medium">
            Hide at (optional)
          </span>
          <input
            type="datetime-local"
            value={until}
            onChange={(e) => setUntil(e.target.value)}
            data-testid={`schedule-until-${product.id}`}
            className="w-full bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2.5 text-sm transition-all"
          />
        </label>

        <div
          className="flex items-start gap-2 rounded-2xl bg-[#FFF9E6] border border-[#E0B53C]/30 p-3"
          data-testid={`schedule-preview-${product.id}`}
        >
          <Clock
            size={14}
            strokeWidth={1.8}
            className="text-[#064E3B] mt-0.5 shrink-0"
          />
          <p className={`text-xs ${valid ? "text-neutral-700" : "text-red-600"}`}>
            {valid ? preview : "End must be after start."}
          </p>
        </div>

        <div className="flex gap-2">
          <button
            onClick={clearAll}
            disabled={saving}
            data-testid={`schedule-clear-${product.id}`}
            className="inline-flex items-center justify-center gap-1.5 rounded-full bg-white border border-black/10 text-neutral-700 hover:bg-neutral-50 py-2.5 px-4 text-xs font-medium transition-all disabled:opacity-50"
          >
            <Trash2 size={13} strokeWidth={1.8} />
            Clear
          </button>
          <button
            onClick={save}
            disabled={saving || !valid}
            data-testid={`schedule-save-${product.id}`}
            className="flex-1 inline-flex items-center justify-center gap-2 bg-[#0B0C10] text-white rounded-full py-2.5 text-sm font-medium hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
          >
            <Save size={14} strokeWidth={1.8} />
            {saving ? "Saving…" : "Save schedule"}
          </button>
        </div>

        <p className="text-[10px] text-neutral-500 text-center leading-relaxed">
          Customers only see products that are Active AND within the schedule
          window. Leave both empty for "always live" (subject to the Live /
          Hidden toggle).
        </p>
      </div>
    </div>
  );
};

// Helper used by the admin product row to derive a Live / Hidden / Scheduled /
// Expired status without duplicating the date arithmetic.
export const computeVisibilityState = (product) => {
  if (product.is_active === false) return "hidden";
  const now = new Date();
  const f = product.active_from ? new Date(product.active_from) : null;
  const u = product.active_until ? new Date(product.active_until) : null;
  if (f && !Number.isNaN(f.getTime()) && f > now) return "scheduled";
  if (u && !Number.isNaN(u.getTime()) && u < now) return "expired";
  return "live";
};

export const visibilityStateLabel = (state) =>
  ({
    hidden: "Hidden",
    scheduled: "Scheduled",
    expired: "Expired",
    live: "Live",
  })[state] || "Live";

export const visibilityHint = (product, state) => {
  if (state === "scheduled" && product.active_from) {
    return `Goes live ${friendlyDelta(product.active_from, "future")}`;
  }
  if (state === "expired" && product.active_until) {
    return `Expired ${friendlyDelta(product.active_until, "past")}`;
  }
  if (state === "live" && product.active_until) {
    return `Live until ${new Date(product.active_until).toLocaleDateString("en-IN", {
      day: "numeric",
      month: "short",
      hour: "2-digit",
      minute: "2-digit",
    })}`;
  }
  return "";
};
