import React, { useState } from "react";
import {
  CheckCircle2,
  Circle,
  Truck,
  Package,
  PackageCheck,
  Ban,
  Send,
  Loader2,
} from "lucide-react";
import { toast } from "sonner";
import { apiUpdateOrderStatus } from "@/lib/api";

const FLOW = ["Placed", "Packed", "Shipped", "Delivered"];
const ICONS = {
  Placed: PackageCheck,
  Packed: Package,
  Shipped: Truck,
  Delivered: CheckCircle2,
};

const isTerminal = (s) => s === "Delivered" || s === "Cancelled";
const nextStatusFor = (current) => {
  if (isTerminal(current)) return null;
  const idx = FLOW.indexOf(current);
  return idx >= 0 && idx < FLOW.length - 1 ? FLOW[idx + 1] : null;
};

export const OrderStatusStepper = ({ order, onUpdated }) => {
  const [busy, setBusy] = useState(false);
  const [tracking, setTracking] = useState(order.tracking_number || "");
  const [cancelOpen, setCancelOpen] = useState(false);
  const [cancelReason, setCancelReason] = useState("");

  const current = order.status || "Placed";
  const next = nextStatusFor(current);
  const cancelled = current === "Cancelled";

  const advance = async () => {
    if (!next || busy) return;
    setBusy(true);
    const t = toast.loading(`Marking as ${next}…`);
    try {
      const extras = next === "Shipped" ? { tracking_number: tracking || undefined } : {};
      const res = await apiUpdateOrderStatus(order.id, next, extras);
      toast.success(`Order marked ${next}`, {
        id: t,
        description: res?.notification?.body
          ? `SMS dispatched · ${res.notification.body.slice(0, 80)}…`
          : "Notification dispatched (mock)",
        duration: 3000,
      });
      onUpdated?.(res.order);
    } catch (e) {
      toast.error(e?.message || `Failed to advance order`, { id: t });
    } finally {
      setBusy(false);
    }
  };

  const cancel = async () => {
    setBusy(true);
    const t = toast.loading("Cancelling order…");
    try {
      const res = await apiUpdateOrderStatus(order.id, "Cancelled", {
        cancel_reason: cancelReason || "Admin cancelled",
      });
      toast.success("Order cancelled", { id: t });
      setCancelOpen(false);
      onUpdated?.(res.order);
    } catch (e) {
      toast.error(e?.message || "Cancel failed", { id: t });
    } finally {
      setBusy(false);
    }
  };

  return (
    <div
      className="rounded-2xl border border-[#022C22]/10 bg-[#FAFAF7]/80 p-4 space-y-3"
      data-testid={`order-status-${order.id}`}
    >
      {/* Pipeline */}
      <ol className="flex items-center gap-1 sm:gap-2 overflow-x-auto">
        {FLOW.map((step, i) => {
          const stepIdx = i;
          const curIdx = FLOW.indexOf(current);
          const reached =
            !cancelled && curIdx >= 0 && stepIdx <= curIdx;
          const Icon = ICONS[step] || Circle;
          return (
            <React.Fragment key={step}>
              <li
                className={`flex items-center gap-1.5 px-2 py-1 rounded-full text-[10px] uppercase tracking-[0.18em] font-medium whitespace-nowrap transition-colors ${
                  cancelled
                    ? "text-red-500 bg-red-50"
                    : reached
                      ? "text-[#064E3B] bg-[#D1FFEB]"
                      : "text-neutral-400 bg-white/60"
                }`}
                data-testid={`order-step-${order.id}-${step.toLowerCase()}`}
              >
                <Icon size={12} strokeWidth={2} />
                <span>{step}</span>
              </li>
              {i < FLOW.length - 1 && (
                <span
                  className={`h-px flex-1 min-w-3 ${
                    cancelled
                      ? "bg-red-200"
                      : !cancelled && FLOW.indexOf(current) > i
                        ? "bg-[#064E3B]/30"
                        : "bg-neutral-200"
                  }`}
                />
              )}
            </React.Fragment>
          );
        })}
      </ol>

      {/* Tracking number visible if shipped or about to ship */}
      {current === "Shipped" && order.tracking_number && (
        <p
          className="text-[11px] text-neutral-600"
          data-testid={`order-tracking-${order.id}`}
        >
          Tracking: <span className="font-mono">{order.tracking_number}</span>
        </p>
      )}
      {next === "Shipped" && (
        <label className="block">
          <span className="block text-[10px] uppercase tracking-[0.18em] text-neutral-500 mb-1">
            Tracking number (optional)
          </span>
          <input
            value={tracking}
            onChange={(e) => setTracking(e.target.value)}
            placeholder="BLU123456IN"
            data-testid={`order-tracking-input-${order.id}`}
            className="w-full bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2 text-sm transition-all"
          />
        </label>
      )}

      {/* Actions */}
      {!isTerminal(current) && (
        <div className="flex items-center gap-2 flex-wrap">
          {next && (
            <button
              type="button"
              onClick={advance}
              disabled={busy}
              data-testid={`order-advance-${order.id}`}
              className="inline-flex items-center gap-1.5 bg-[#022C22] text-[#E0B53C] rounded-full px-4 py-2 text-xs font-medium hover:bg-[#053f30] transition-all disabled:opacity-60"
            >
              {busy ? (
                <Loader2 size={13} strokeWidth={2} className="animate-spin" />
              ) : (
                <Send size={13} strokeWidth={2} />
              )}
              Mark {next}
            </button>
          )}
          <button
            type="button"
            onClick={() => setCancelOpen(true)}
            disabled={busy}
            data-testid={`order-cancel-${order.id}`}
            className="inline-flex items-center gap-1.5 bg-white text-red-600 border border-red-200 rounded-full px-4 py-2 text-xs font-medium hover:bg-red-50 transition-all disabled:opacity-60"
          >
            <Ban size={13} strokeWidth={2} />
            Cancel
          </button>
        </div>
      )}

      {cancelled && order.cancel_reason && (
        <p
          className="text-[11px] text-red-500"
          data-testid={`order-cancel-reason-${order.id}`}
        >
          Cancelled: {order.cancel_reason}
        </p>
      )}

      {/* Cancel confirm */}
      {cancelOpen && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4"
          onClick={() => !busy && setCancelOpen(false)}
          data-testid={`order-cancel-dialog-${order.id}`}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            className="w-full max-w-sm rounded-3xl bg-white shadow-2xl border border-white/60 p-6 space-y-4"
          >
            <h3 className="font-display text-xl text-[#0B0C10]">
              Cancel order?
            </h3>
            <p className="text-sm text-neutral-600">
              The customer will receive a cancellation SMS. This cannot be
              reverted.
            </p>
            <label className="block">
              <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-500 mb-1">
                Reason (optional)
              </span>
              <input
                value={cancelReason}
                onChange={(e) => setCancelReason(e.target.value)}
                placeholder="Out of stock, customer request, etc."
                data-testid={`order-cancel-reason-input-${order.id}`}
                className="w-full bg-white border border-black/10 focus:border-red-400 focus:ring-1 focus:ring-red-200 outline-none rounded-xl px-3 py-2 text-sm transition-all"
              />
            </label>
            <div className="flex gap-2">
              <button
                onClick={() => setCancelOpen(false)}
                disabled={busy}
                className="flex-1 rounded-full bg-neutral-100 hover:bg-neutral-200 py-2.5 text-sm font-medium transition-all disabled:opacity-50"
              >
                Keep order
              </button>
              <button
                onClick={cancel}
                disabled={busy}
                data-testid={`order-cancel-confirm-${order.id}`}
                className="flex-1 rounded-full bg-red-600 text-white py-2.5 text-sm font-medium hover:bg-red-700 transition-all disabled:opacity-50"
              >
                {busy ? "Cancelling…" : "Cancel order"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};
