import React, { useEffect, useState } from "react";
import { IndianRupee, Loader2, Check, FolderInput } from "lucide-react";
import { toast } from "sonner";
import {
  apiListCategories,
  apiUpdateProductPrice,
  apiUpdateProductCategory,
} from "@/lib/api";

// Lazy-loaded, cached list of category names for the folder dropdown.
let _catCache = null;
const loadCategoryNames = async () => {
  if (_catCache) return _catCache;
  const items = await apiListCategories({ includeInactive: true });
  _catCache = items.map((c) => c.name);
  return _catCache;
};
export const invalidateCategoryCache = () => {
  _catCache = null;
};

const formatINR = (n) =>
  `₹${Number(n).toLocaleString("en-IN", { maximumFractionDigits: 0 })}`;

// Inline quick-edit strip: direct selling price + folder swap dropdown.
// Sits inside each admin product row. Debounced, optimistic, small footprint.
export const ProductQuickEdit = ({ product, onSaved }) => {
  const [price, setPrice] = useState(String(product.price ?? ""));
  const [savingPrice, setSavingPrice] = useState(false);
  const [category, setCategory] = useState(product.category || "");
  const [savingCat, setSavingCat] = useState(false);
  const [cats, setCats] = useState([]);

  useEffect(() => {
    setPrice(String(product.price ?? ""));
    setCategory(product.category || "");
  }, [product.id, product.price, product.category]);

  useEffect(() => {
    loadCategoryNames().then(setCats).catch(() => setCats([product.category].filter(Boolean)));
  }, [product.category]);

  const commitPrice = async () => {
    const next = Number(price);
    if (Number.isNaN(next) || next < 0 || next === Number(product.price)) return;
    setSavingPrice(true);
    try {
      await apiUpdateProductPrice(product.id, next);
      toast.success(`Price set to ${formatINR(next)}`, { duration: 1400 });
      onSaved?.();
    } catch (err) {
      toast.error(err?.message || "Failed to save price");
      setPrice(String(product.price ?? ""));
    } finally {
      setSavingPrice(false);
    }
  };

  const commitCategory = async (next) => {
    if (!next || next === product.category) return;
    setCategory(next);
    setSavingCat(true);
    try {
      await apiUpdateProductCategory(product.id, next);
      toast.success(`Moved to ${next}`, { duration: 1400 });
      onSaved?.();
    } catch (err) {
      toast.error(err?.message || "Failed to move");
      setCategory(product.category || "");
    } finally {
      setSavingCat(false);
    }
  };

  // Include the current category in the list even if it isn't in the master
  // folder set (so custom/legacy categories don't disappear from the picker).
  const options = React.useMemo(() => {
    const set = new Set(cats);
    if (product.category) set.add(product.category);
    return Array.from(set).sort();
  }, [cats, product.category]);

  return (
    <div className="mt-1.5 flex flex-wrap items-center gap-2">
      <div
        className="relative inline-flex items-center"
        data-testid={`admin-quick-price-${product.id}`}
      >
        <IndianRupee
          size={12}
          strokeWidth={2}
          className="absolute left-2 top-1/2 -translate-y-1/2 text-neutral-500 pointer-events-none"
        />
        <input
          type="number"
          min="0"
          step="1"
          value={price}
          onChange={(e) => setPrice(e.target.value)}
          onBlur={commitPrice}
          onKeyDown={(e) => {
            if (e.key === "Enter") {
              e.preventDefault();
              e.target.blur();
            }
          }}
          disabled={savingPrice}
          data-testid={`admin-quick-price-input-${product.id}`}
          aria-label="Selling price"
          className="w-24 bg-white border border-black/15 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-lg pl-6 pr-6 py-1 text-xs font-medium text-[#0B0C10] transition-all"
        />
        {savingPrice ? (
          <Loader2
            size={12}
            className="absolute right-1.5 top-1/2 -translate-y-1/2 animate-spin text-neutral-400"
          />
        ) : (
          Number(price) !== Number(product.price) && (
            <Check
              size={12}
              strokeWidth={2}
              className="absolute right-1.5 top-1/2 -translate-y-1/2 text-[#064E3B]"
            />
          )
        )}
      </div>

      <div className="relative inline-flex items-center">
        <FolderInput
          size={12}
          strokeWidth={1.8}
          className="absolute left-2 top-1/2 -translate-y-1/2 text-neutral-500 pointer-events-none"
        />
        <select
          value={category}
          onChange={(e) => commitCategory(e.target.value)}
          disabled={savingCat}
          data-testid={`admin-quick-folder-${product.id}`}
          aria-label="Move to folder"
          className="max-w-[10rem] appearance-none bg-white border border-black/15 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-lg pl-6 pr-2 py-1 text-xs font-medium text-[#0B0C10] transition-all truncate"
        >
          {options.map((c) => (
            <option key={c} value={c}>
              {c}
            </option>
          ))}
        </select>
        {savingCat && (
          <Loader2
            size={12}
            className="absolute right-1.5 top-1/2 -translate-y-1/2 animate-spin text-neutral-400"
          />
        )}
      </div>
    </div>
  );
};
