import React, { useEffect, useState } from "react";
import { Image as ImageIcon, Trash2, Upload, Save } from "lucide-react";
import { toast } from "sonner";
import {
  apiDeleteBanner,
  apiListBanners,
  apiUploadIfDataUrl,
  apiUpsertBanner,
} from "@/lib/api";
import { CATEGORIES } from "@/lib/constants";
import { LazyImage } from "./LazyImage";

const fileToDataUrl = (file) =>
  new Promise((resolve, reject) => {
    const r = new FileReader();
    r.onload = () => resolve(r.result);
    r.onerror = () => reject(new Error("read failed"));
    r.readAsDataURL(file);
  });

export const BannerManager = () => {
  const [banners, setBanners] = useState([]);
  const [loading, setLoading] = useState(true);
  const [busyCat, setBusyCat] = useState("");

  const reload = async () => {
    setLoading(true);
    try {
      const list = await apiListBanners();
      setBanners(list);
    } catch (e) {
      toast.error(`Failed to load banners: ${e.message}`);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    reload();
  }, []);

  const handleFile = async (category, file) => {
    if (!file) return;
    if (!file.type.startsWith("image/")) {
      toast.error("Please choose an image");
      return;
    }
    setBusyCat(category);
    try {
      const dataUrl = await fileToDataUrl(file);
      const url = await apiUploadIfDataUrl(dataUrl);
      await apiUpsertBanner(category, url);
      toast.success(`${category} banner saved`, { duration: 1800 });
      await reload();
    } catch (e) {
      toast.error(`Upload failed: ${e.message}`);
    } finally {
      setBusyCat("");
    }
  };

  const handleDelete = async (category) => {
    setBusyCat(category);
    try {
      await apiDeleteBanner(category);
      toast.success(`${category} banner removed`, { duration: 1600 });
      await reload();
    } catch (e) {
      toast.error(`Delete failed: ${e.message}`);
    } finally {
      setBusyCat("");
    }
  };

  const byCategory = Object.fromEntries(banners.map((b) => [b.category, b]));

  return (
    <div className="space-y-3" data-testid="admin-banner-manager">
      <div className="rounded-3xl border border-white/60 bg-white/75 backdrop-blur-2xl p-5 sm:p-7">
        <div className="flex items-center gap-2 mb-1">
          <ImageIcon size={16} strokeWidth={1.8} className="text-[#064E3B]" />
          <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
            Category banners
          </span>
        </div>
        <p className="text-sm text-neutral-600 mb-5">
          One banner per category. Shown above the storefront when a customer
          picks that category. {loading ? "Loading…" : `${banners.length} configured.`}
        </p>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {CATEGORIES.map((cat) => {
            const b = byCategory[cat];
            const busy = busyCat === cat;
            return (
              <div
                key={cat}
                data-testid={`banner-row-${cat.toLowerCase()}`}
                className="rounded-2xl border border-white/60 bg-white/80 p-4 space-y-3"
              >
                <div className="flex items-center justify-between">
                  <p className="text-[11px] uppercase tracking-[0.22em] text-[#0B0C10] font-semibold">
                    {cat}
                  </p>
                  {b ? (
                    <span className="text-[10px] uppercase tracking-[0.18em] text-[#064E3B] bg-[#D1FFEB] px-2 py-0.5 rounded-full">
                      Live
                    </span>
                  ) : (
                    <span className="text-[10px] uppercase tracking-[0.18em] text-neutral-500 bg-neutral-100 px-2 py-0.5 rounded-full">
                      Empty
                    </span>
                  )}
                </div>

                <div className="relative aspect-[16/6] rounded-xl overflow-hidden bg-neutral-100 border border-black/5">
                  {b ? (
                    <LazyImage
                      src={b.image}
                      alt={`${cat} banner`}
                      wrapperClassName="w-full h-full"
                      className="absolute inset-0 w-full h-full object-cover"
                    />
                  ) : (
                    <div className="absolute inset-0 flex items-center justify-center text-xs text-neutral-400">
                      No banner yet
                    </div>
                  )}
                </div>

                <div className="flex items-center gap-2">
                  <label
                    className={`inline-flex items-center gap-1.5 px-3 py-2 rounded-full text-xs font-medium cursor-pointer transition-all ${
                      busy
                        ? "bg-neutral-200 text-neutral-500 cursor-wait"
                        : "bg-[#022C22] text-[#E0B53C] hover:bg-[#053f30]"
                    }`}
                    data-testid={`banner-upload-${cat.toLowerCase()}`}
                  >
                    <Upload size={13} strokeWidth={1.8} />
                    {busy ? "Saving…" : b ? "Replace" : "Upload"}
                    <input
                      type="file"
                      accept="image/*"
                      onChange={(e) => handleFile(cat, e.target.files?.[0])}
                      disabled={busy}
                      className="hidden"
                    />
                  </label>
                  {b && (
                    <button
                      type="button"
                      onClick={() => handleDelete(cat)}
                      disabled={busy}
                      data-testid={`banner-delete-${cat.toLowerCase()}`}
                      className="inline-flex items-center gap-1.5 px-3 py-2 rounded-full text-xs font-medium bg-white border border-black/10 text-neutral-700 hover:bg-red-50 hover:text-red-600 transition-all disabled:opacity-50"
                    >
                      <Trash2 size={13} strokeWidth={1.8} />
                      Remove
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>

        <div className="flex items-center gap-2 mt-5 text-[11px] text-neutral-500">
          <Save size={12} strokeWidth={1.8} />
          Recommended dimensions: 1600×600px (16:6 aspect). PNG / JPEG / WebP up to ~2MB.
        </div>
      </div>
    </div>
  );
};
