import React, { useEffect, useState } from "react";
import { Loader2, RotateCcw, Phone, IndianRupee, ImageIcon, Download } from "lucide-react";
import { toast } from "sonner";
import { apiListReturns, apiUpdateReturnStatus } from "@/lib/api";

const STATUS = ["Pending", "Approved", "Rejected", "Refunded"];
const STATUS_COLOR = {
  Pending: "bg-amber-100 text-amber-800 border-amber-200",
  Approved: "bg-blue-100 text-blue-800 border-blue-200",
  Refunded: "bg-emerald-100 text-emerald-800 border-emerald-200",
  Rejected: "bg-red-100 text-red-700 border-red-200",
};

export const ReturnsTab = () => {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);

  const reload = async () => {
    try {
      const items = await apiListReturns();
      setRows(items || []);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    reload();
  }, []);

  const updateStatus = async (id, status) => {
    setRows((prev) => prev.map((r) => (r.id === id ? { ...r, status } : r)));
    try {
      await apiUpdateReturnStatus(id, status);
      toast.success(`Marked ${status}`, { duration: 1200 });
    } catch (err) {
      toast.error(err?.message || "Failed to update");
      await reload();
    }
  };

  if (loading) {
    return (
      <div className="p-10 text-center text-neutral-500">
        <Loader2 size={20} className="animate-spin mx-auto" />
      </div>
    );
  }

  if (rows.length === 0) {
    return (
      <div className="rounded-3xl border border-white/60 bg-white/60 backdrop-blur-xl p-10 text-center">
        <RotateCcw size={28} strokeWidth={1.5} className="mx-auto mb-4 text-neutral-400" />
        <p className="font-display text-xl text-[#0B0C10] mb-1">No return requests yet.</p>
        <p className="text-sm text-neutral-600">
          Customers can file returns from their profile menu.
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-3" data-testid="admin-returns-list">
      {rows.map((r) => (
        <div
          key={r.id}
          data-testid={`admin-return-row-${r.id}`}
          className="rounded-2xl border border-white/60 bg-white/75 backdrop-blur-xl p-4 sm:p-5 space-y-3"
        >
          <div className="flex items-start gap-4">
            {(() => {
              const photos = Array.isArray(r.photo_urls) && r.photo_urls.length
                ? r.photo_urls
                : (r.photo_url ? [r.photo_url] : []);
              return (
                <div
                  className="flex gap-2 shrink-0"
                  data-testid={`admin-return-photos-${r.id}`}
                >
                  {[0, 1].map((slot) => {
                    const url = photos[slot];
                    return url ? (
                      <div
                        key={slot}
                        className="relative w-20 h-20 rounded-xl overflow-hidden bg-white border border-black/10 group"
                        data-testid={`admin-return-photo-${r.id}-${slot}`}
                      >
                        <a
                          href={url}
                          target="_blank"
                          rel="noreferrer"
                          className="block w-full h-full"
                        >
                          <img
                            src={url}
                            alt={`return ${slot + 1}`}
                            loading="lazy"
                            className="w-full h-full object-cover"
                          />
                        </a>
                        <a
                          href={url}
                          download={`return-${r.id}-photo-${slot + 1}.jpg`}
                          data-testid={`admin-return-download-${r.id}-${slot}`}
                          aria-label={`download photo ${slot + 1}`}
                          className="absolute bottom-1 right-1 w-6 h-6 rounded-full bg-white/95 text-[#064E3B] flex items-center justify-center shadow opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <Download size={12} strokeWidth={2} />
                        </a>
                      </div>
                    ) : (
                      <div
                        key={slot}
                        className="w-20 h-20 rounded-xl bg-neutral-100 flex items-center justify-center text-neutral-400"
                      >
                        <ImageIcon size={18} strokeWidth={1.5} />
                      </div>
                    );
                  })}
                </div>
              );
            })()}
            <div className="flex-1 min-w-0 space-y-1.5">
              <div className="flex items-baseline gap-2 flex-wrap">
                <span className="font-mono text-[11px] text-neutral-500 truncate">
                  #{r.id}
                </span>
                <span
                  className={`text-[10px] uppercase tracking-[0.14em] font-semibold rounded-full border px-2 py-0.5 ${STATUS_COLOR[r.status] || "bg-neutral-100"}`}
                >
                  {r.status}
                </span>
              </div>
              {r.customer_name && (
                <p
                  className="text-sm font-semibold text-[#0B0C10] truncate"
                  data-testid={`admin-return-customer-${r.id}`}
                >
                  {r.customer_name}
                </p>
              )}
              <div className="flex items-center gap-1.5 text-sm text-[#0B0C10]">
                <Phone size={13} strokeWidth={1.8} className="text-neutral-400" />
                <span className="font-medium truncate">{r.order_id_or_phone}</span>
              </div>
              <p className="text-sm text-neutral-700">
                <span className="text-[10px] uppercase tracking-[0.18em] text-neutral-500 mr-2">
                  Reason
                </span>
                <span data-testid={`admin-return-reason-${r.id}`}>{r.reason}</span>
              </p>
              <p className="text-sm text-neutral-700 flex items-start gap-1.5">
                <IndianRupee size={13} strokeWidth={1.8} className="text-neutral-400 mt-0.5 shrink-0" />
                <span className="whitespace-pre-wrap break-words">{r.refund_details}</span>
              </p>
              {r.notes && (
                <p className="text-xs text-neutral-500 whitespace-pre-wrap break-words">
                  {r.notes}
                </p>
              )}
              <p className="text-[10px] text-neutral-400">
                {new Date(r.created_at).toLocaleString("en-IN", {
                  dateStyle: "medium",
                  timeStyle: "short",
                })}
              </p>
            </div>
          </div>
          <div className="flex flex-wrap gap-2">
            {STATUS.map((s) => (
              <button
                key={s}
                type="button"
                onClick={() => updateStatus(r.id, s)}
                disabled={r.status === s}
                data-testid={`admin-return-status-${r.id}-${s}`}
                className={`text-[11px] font-medium rounded-full px-3 py-1.5 border transition-all ${
                  r.status === s
                    ? "bg-[#0B0C10] text-white border-[#0B0C10]"
                    : "bg-white text-[#0B0C10] border-black/15 hover:border-[#0B0C10]"
                } disabled:opacity-60`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};
