import React, { useEffect, useMemo, useState } from "react";
import { Folder, FolderOpen, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { apiListCategories, apiUpdateCategoryVisibility } from "@/lib/api";

// Admin folders tab — full nested tree with per-row ON/OFF toggle.
// Turning a parent off hides all descendants on the storefront in real time
// (server enforces this in list_products and list_categories).
export const FoldersTab = () => {
  const [rows, setRows] = useState([]);
  const [loading, setLoading] = useState(true);
  const [savingId, setSavingId] = useState(null);

  const reload = async () => {
    try {
      const items = await apiListCategories({ includeInactive: true });
      setRows(items);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    reload();
  }, []);

  const tree = useMemo(() => {
    const parents = rows.filter((r) => !r.parent_id);
    return parents.map((p) => ({
      ...p,
      children: rows
        .filter((r) => r.parent_id === p.id)
        .sort((a, b) => (a.sort_order ?? 0) - (b.sort_order ?? 0)),
    }));
  }, [rows]);

  const toggle = async (row, next) => {
    setSavingId(row.id);
    setRows((prev) =>
      prev.map((r) => (r.id === row.id ? { ...r, is_active: next } : r)),
    );
    try {
      await apiUpdateCategoryVisibility(row.id, next);
      toast.success(`${row.name} ${next ? "shown" : "hidden"}`, {
        duration: 1400,
      });
      // Notify storefront to refresh categories/products immediately.
      window.dispatchEvent(new Event("mb-categories-change"));
    } catch (err) {
      setRows((prev) =>
        prev.map((r) => (r.id === row.id ? { ...r, is_active: !next } : r)),
      );
      toast.error(err?.message || "Failed to update");
    } finally {
      setSavingId(null);
    }
  };

  if (loading) {
    return (
      <div className="p-10 text-center text-neutral-500">
        <Loader2 size={20} className="animate-spin mx-auto" />
      </div>
    );
  }

  return (
    <div className="space-y-3" data-testid="admin-folders-list">
      <p className="text-xs text-neutral-600">
        Turn a folder OFF to instantly hide it (and everything inside) from the
        storefront. Turn it back ON to make it visible again.
      </p>
      {tree.map((p) => (
        <div
          key={p.id}
          className="rounded-2xl border border-white/60 bg-white/75 backdrop-blur-xl p-4"
          data-testid={`admin-folder-parent-${p.id}`}
        >
          <FolderRow row={p} saving={savingId === p.id} onToggle={toggle} isParent />
          {p.children.length > 0 && (
            <div className="mt-3 pl-6 border-l border-black/10 space-y-2">
              {p.children.map((c) => (
                <FolderRow
                  key={c.id}
                  row={c}
                  saving={savingId === c.id}
                  onToggle={toggle}
                  parentDisabled={!p.is_active}
                />
              ))}
            </div>
          )}
        </div>
      ))}
    </div>
  );
};

const FolderRow = ({ row, saving, onToggle, isParent, parentDisabled }) => {
  const active = !!row.is_active;
  const Icon = active ? FolderOpen : Folder;
  return (
    <div
      className="flex items-center justify-between gap-3"
      data-testid={`admin-folder-row-${row.id}`}
    >
      <div className="flex items-center gap-2 min-w-0">
        <Icon
          size={isParent ? 16 : 14}
          strokeWidth={1.6}
          className={active ? "text-[#064E3B]" : "text-neutral-400"}
        />
        <span
          className={`truncate ${
            isParent ? "font-display text-base text-[#0B0C10]" : "text-sm text-neutral-700"
          } ${!active ? "line-through opacity-60" : ""}`}
        >
          {row.name}
        </span>
        {parentDisabled && (
          <span className="text-[9px] uppercase tracking-[0.18em] text-neutral-400 ml-1">
            (parent off)
          </span>
        )}
      </div>
      <button
        type="button"
        onClick={() => onToggle(row, !active)}
        disabled={saving}
        role="switch"
        aria-checked={active}
        data-testid={`admin-folder-toggle-${row.id}`}
        className={`shrink-0 relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
          active ? "bg-[#064E3B]" : "bg-neutral-300"
        } disabled:opacity-60`}
      >
        <span
          className={`inline-block h-5 w-5 transform rounded-full bg-white transition-transform ${
            active ? "translate-x-5" : "translate-x-0.5"
          }`}
        />
      </button>
    </div>
  );
};
