import React, { useEffect, useRef, useState } from "react";
import { Loader2, Upload, ImagePlus, Trash2, RefreshCcw } from "lucide-react";
import { toast } from "sonner";
import {
  apiGetBranding,
  apiSetBranding,
  apiUploadIfDataUrl,
} from "@/lib/api";

// Admin App Branding module — upload a new master logo. On save, the URL is
// stored in the settings collection and broadcast via a browser event so
// every BrandMark instance in the app re-reads and re-renders immediately.
export const BrandingTab = () => {
  const [logoUrl, setLogoUrl] = useState("");
  const [uploading, setUploading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);
  const fileRef = useRef(null);

  useEffect(() => {
    apiGetBranding()
      .then((d) => setLogoUrl(d?.logo_url || ""))
      .finally(() => setLoading(false));
  }, []);

  const commit = async (url) => {
    setSaving(true);
    try {
      await apiSetBranding(url);
      setLogoUrl(url);
      window.dispatchEvent(
        new CustomEvent("mb-branding-change", { detail: { logoUrl: url } }),
      );
      toast.success(url ? "Logo updated" : "Logo reset to default", {
        duration: 1600,
      });
    } catch (err) {
      toast.error(err?.message || "Failed to save");
    } finally {
      setSaving(false);
    }
  };

  const handleFile = async (e) => {
    const file = e.target.files?.[0];
    e.target.value = "";
    if (!file || !file.type.startsWith("image/")) {
      toast.error("Please pick a valid image file.");
      return;
    }
    setUploading(true);
    const t = toast.loading("Uploading logo…");
    try {
      const dataUrl = await new Promise((res, rej) => {
        const r = new FileReader();
        r.onload = () => res(r.result);
        r.onerror = () => rej(r.error);
        r.readAsDataURL(file);
      });
      const url = await apiUploadIfDataUrl(dataUrl);
      await commit(url);
      toast.success("Logo uploaded", { id: t, duration: 1600 });
    } catch (err) {
      toast.error(err?.message || "Upload failed", { id: t });
    } finally {
      setUploading(false);
    }
  };

  if (loading) {
    return (
      <div className="p-10 text-center text-neutral-500">
        <Loader2 size={20} className="animate-spin mx-auto" />
      </div>
    );
  }

  return (
    <div
      className="rounded-3xl border border-white/60 bg-white/75 backdrop-blur-xl p-6 space-y-6"
      data-testid="admin-branding-tab"
    >
      <div>
        <p className="text-[10px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
          App Branding / Logo Settings
        </p>
        <h2 className="font-display text-2xl text-[#0B0C10] mt-1">
          Master site logo
        </h2>
        <p className="text-sm text-neutral-600 mt-1 leading-relaxed">
          Upload an image to replace the site &amp; app logo everywhere in
          real time — header, splash screen, PWA install icon, coming-soon
          gate. Leave empty to fall back to the default premium mark.
        </p>
      </div>

      <div className="flex items-center gap-5">
        <div
          className="w-24 h-24 rounded-2xl bg-neutral-50 border border-black/10 overflow-hidden flex items-center justify-center"
          data-testid="admin-branding-preview"
        >
          {logoUrl ? (
            <img
              src={logoUrl}
              alt="current logo"
              className="w-full h-full object-contain"
            />
          ) : (
            <ImagePlus size={22} strokeWidth={1.4} className="text-neutral-400" />
          )}
        </div>
        <div className="flex-1 min-w-0">
          <input
            ref={fileRef}
            type="file"
            accept="image/*"
            onChange={handleFile}
            data-testid="admin-branding-file-input"
            className="hidden"
          />
          <button
            type="button"
            onClick={() => fileRef.current?.click()}
            disabled={uploading || saving}
            data-testid="admin-branding-upload-btn"
            className="inline-flex items-center gap-2 bg-[#022C22] text-[#E0B53C] rounded-xl px-4 py-2.5 text-sm font-medium disabled:opacity-60 hover:-translate-y-0.5 transition-all"
          >
            {uploading || saving ? (
              <Loader2 size={14} className="animate-spin" />
            ) : (
              <Upload size={14} />
            )}
            {logoUrl ? "Replace logo" : "Upload logo"}
          </button>
          {logoUrl && (
            <button
              type="button"
              onClick={() => commit("")}
              disabled={saving}
              data-testid="admin-branding-reset-btn"
              className="ml-2 inline-flex items-center gap-1.5 text-xs font-medium text-red-600 hover:text-white hover:bg-red-600 border border-red-200 hover:border-red-600 rounded-full px-3 py-1.5 transition-colors disabled:opacity-60"
            >
              <Trash2 size={12} strokeWidth={1.8} />
              Reset to default
            </button>
          )}
          <p className="text-[10px] text-neutral-500 mt-2">
            PNG/JPG/SVG · Square 1:1 aspect ratio works best (min 512×512).
          </p>
        </div>
      </div>

      <div className="rounded-2xl bg-neutral-50 border border-black/5 p-4 text-[11px] text-neutral-600 leading-relaxed">
        <p className="font-semibold text-[#0B0C10] mb-1 flex items-center gap-1.5">
          <RefreshCcw size={12} strokeWidth={1.8} />
          Live sync
        </p>
        Changes propagate instantly to all open browser tabs and to the app
        header the moment you upload. No redeploy or reload required.
      </div>
    </div>
  );
};
