import React, { useState } from "react";
import { CheckSquare, XSquare, Layers, Loader2 } from "lucide-react";
import { toast } from "sonner";
import { apiBulkVisibility } from "@/lib/api";

// Bulk publish / hide controls for the admin Products tab. Either targets ALL
// products or narrows to a single category. Always behind a confirm step so
// no accidental wipes.
export const BulkVisibilityBar = ({ products, categories, onChanged }) => {
  const [busy, setBusy] = useState(false);
  const [confirmFor, setConfirmFor] = useState(null); // {isActive, category|null}
  const [category, setCategory] = useState("");

  const visibleCats = categories.filter(Boolean);

  const scopeCount = (cat) =>
    cat ? products.filter((p) => p.category === cat).length : products.length;

  const run = async () => {
    if (!confirmFor) return;
    const { isActive, category: cat } = confirmFor;
    setBusy(true);
    const t = toast.loading(
      `${isActive ? "Publishing" : "Hiding"} ${scopeCount(cat)} product(s)…`,
    );
    try {
      const res = await apiBulkVisibility({
        isActive,
        category: cat || undefined,
      });
      toast.success(
        `${isActive ? "Published" : "Hidden"} ${res.matched} product(s)`,
        { id: t, duration: 2200 },
      );
      onChanged?.();
      setConfirmFor(null);
    } catch (e) {
      toast.error(e?.message || "Bulk update failed", { id: t });
    } finally {
      setBusy(false);
    }
  };

  return (
    <>
      <div
        className="rounded-2xl border border-white/60 bg-white/75 backdrop-blur-xl p-3 sm:p-4 flex flex-col sm:flex-row sm:items-center gap-3"
        data-testid="bulk-visibility-bar"
      >
        <div className="flex items-center gap-2 shrink-0">
          <Layers size={14} strokeWidth={1.8} className="text-[#064E3B]" />
          <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
            Bulk actions
          </span>
        </div>
        <select
          value={category}
          onChange={(e) => setCategory(e.target.value)}
          data-testid="bulk-category-select"
          className="bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] outline-none rounded-xl px-3 py-2 text-xs transition-all flex-1 sm:flex-none sm:min-w-[180px]"
        >
          <option value="">All categories ({products.length})</option>
          {visibleCats.map((c) => (
            <option key={c} value={c}>
              {c} ({scopeCount(c)})
            </option>
          ))}
        </select>
        <div className="flex items-center gap-2 ml-auto">
          <button
            type="button"
            onClick={() =>
              setConfirmFor({ isActive: true, category: category || null })
            }
            disabled={busy || products.length === 0}
            data-testid="bulk-publish-btn"
            className="inline-flex items-center gap-1.5 bg-[#022C22] text-[#E0B53C] rounded-full px-4 py-2 text-xs font-medium hover:bg-[#053f30] transition-all disabled:opacity-60"
          >
            <CheckSquare size={13} strokeWidth={2} />
            Publish {category ? "category" : "all"}
          </button>
          <button
            type="button"
            onClick={() =>
              setConfirmFor({ isActive: false, category: category || null })
            }
            disabled={busy || products.length === 0}
            data-testid="bulk-hide-btn"
            className="inline-flex items-center gap-1.5 bg-white text-neutral-700 border border-black/10 rounded-full px-4 py-2 text-xs font-medium hover:bg-neutral-50 transition-all disabled:opacity-60"
          >
            <XSquare size={13} strokeWidth={2} />
            Hide {category ? "category" : "all"}
          </button>
        </div>
      </div>

      {confirmFor && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center bg-black/45 backdrop-blur-sm p-4"
          onClick={() => !busy && setConfirmFor(null)}
          data-testid="bulk-confirm-dialog"
        >
          <div
            onClick={(e) => e.stopPropagation()}
            className="w-full max-w-sm rounded-3xl bg-white shadow-2xl border border-white/60 p-6 space-y-4"
          >
            <h3 className="font-display text-xl text-[#0B0C10]">
              {confirmFor.isActive ? "Publish" : "Hide"}{" "}
              {confirmFor.category ? `all ${confirmFor.category}` : "every product"}
              ?
            </h3>
            <p className="text-sm text-neutral-600">
              This will flip <strong>{scopeCount(confirmFor.category)}</strong>{" "}
              product{scopeCount(confirmFor.category) === 1 ? "" : "s"} to{" "}
              <strong>{confirmFor.isActive ? "Live" : "Hidden"}</strong>{" "}
              instantly. Individual schedules will be preserved.
            </p>
            <div className="flex gap-2">
              <button
                onClick={() => setConfirmFor(null)}
                disabled={busy}
                className="flex-1 rounded-full bg-neutral-100 hover:bg-neutral-200 py-2.5 text-sm font-medium transition-all disabled:opacity-50"
              >
                Cancel
              </button>
              <button
                onClick={run}
                disabled={busy}
                data-testid="bulk-confirm-btn"
                className={`flex-1 inline-flex items-center justify-center gap-1.5 rounded-full py-2.5 text-sm font-medium transition-all disabled:opacity-50 ${
                  confirmFor.isActive
                    ? "bg-[#022C22] text-[#E0B53C] hover:bg-[#053f30]"
                    : "bg-neutral-900 text-white hover:bg-black"
                }`}
              >
                {busy ? (
                  <Loader2 size={13} strokeWidth={2} className="animate-spin" />
                ) : confirmFor.isActive ? (
                  <CheckSquare size={13} strokeWidth={2} />
                ) : (
                  <XSquare size={13} strokeWidth={2} />
                )}
                {confirmFor.isActive ? "Publish" : "Hide"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
};
