import React, { useEffect, useState } from "react";
import { Box, Save, X } from "lucide-react";
import { toast } from "sonner";
import { apiUpdateStock } from "@/lib/api";

// Inline editor for per-size stock counts on an existing product.
// Renders inside a small popover next to each product row in the admin list.
export const StockGrid = ({ product, onClose, onSaved }) => {
  const sizes =
    Array.isArray(product.sizes) && product.sizes.length > 0
      ? product.sizes
      : ["Free Size"];

  const [draft, setDraft] = useState(() => {
    const stock = product.stock_by_size || {};
    const out = {};
    sizes.forEach((s) => {
      out[s] = Number.isFinite(stock[s]) ? stock[s] : 0;
    });
    return out;
  });
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "Escape") onClose?.();
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [onClose]);

  const save = async () => {
    setSaving(true);
    try {
      const cleaned = {};
      for (const [k, v] of Object.entries(draft)) {
        const n = Number(v);
        cleaned[k] = Number.isFinite(n) ? Math.max(0, Math.floor(n)) : 0;
      }
      const updated = await apiUpdateStock(product.id, cleaned);
      toast.success("Stock updated", { duration: 1500 });
      onSaved?.(updated);
      onClose?.();
    } catch (e) {
      toast.error(`Update failed: ${e.message}`);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div
      className="fixed inset-0 z-50 flex items-center justify-center bg-black/40 backdrop-blur-sm p-4"
      onClick={onClose}
      data-testid={`stock-grid-${product.id}`}
    >
      <div
        onClick={(e) => e.stopPropagation()}
        className="w-full max-w-md rounded-3xl bg-white shadow-2xl border border-white/60 p-6"
      >
        <div className="flex items-start justify-between gap-3 mb-4">
          <div>
            <div className="flex items-center gap-2 mb-1">
              <Box size={14} strokeWidth={1.8} className="text-[#064E3B]" />
              <span className="text-[11px] uppercase tracking-[0.22em] text-[#064E3B] font-semibold">
                Stock per size
              </span>
            </div>
            <h3 className="font-display text-xl text-[#0B0C10] line-clamp-1">
              {product.title}
            </h3>
          </div>
          <button
            onClick={onClose}
            className="p-2 rounded-full hover:bg-neutral-100"
            data-testid="stock-grid-close"
          >
            <X size={16} strokeWidth={1.8} />
          </button>
        </div>

        <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
          {sizes.map((size) => (
            <label
              key={size}
              className="block rounded-xl border border-black/10 bg-white p-3"
            >
              <span className="block text-[11px] uppercase tracking-[0.18em] text-neutral-600 mb-1.5 font-medium">
                Size {size}
              </span>
              <input
                type="number"
                min={0}
                value={draft[size] ?? 0}
                onChange={(e) =>
                  setDraft((p) => ({ ...p, [size]: e.target.value }))
                }
                data-testid={`stock-input-${product.id}-${size.replace(/\s+/g, "-")}`}
                className="w-full outline-none bg-white border border-black/10 focus:border-[#0B0C10] focus:ring-1 focus:ring-[#0B0C10] rounded-lg px-3 py-2 text-sm font-medium transition-all"
              />
            </label>
          ))}
        </div>

        <button
          onClick={save}
          disabled={saving}
          data-testid="stock-grid-save"
          className="w-full mt-5 inline-flex items-center justify-center gap-2 bg-[#0B0C10] text-white rounded-full py-3 text-sm font-medium hover:-translate-y-0.5 hover:shadow-lg transition-all disabled:opacity-60"
        >
          <Save size={14} strokeWidth={1.8} />
          {saving ? "Saving…" : "Save stock"}
        </button>
        <p className="text-[11px] text-neutral-500 text-center mt-2">
          Customers cannot order a size with 0 in stock. Sizes count down
          automatically as orders come in.
        </p>
      </div>
    </div>
  );
};
