// Free, client-side AI-style image enhancement pipeline for MastiBazaar.
// No external API, no paid SDK — pure Canvas + typed-array math.
//
// Steps:
//   1. Resolution balance  → cap longest edge to `maxDim` with high-quality
//      bilinear downscale (browser-native imageSmoothingQuality: "high").
//   2. Tone pass           → brightness, contrast, saturation in one loop.
//   3. Unsharp mask        → 3×3 convolution sharpen with edge-safe handling.
//   4. JPEG re-encode      → tuned quality (0.92) for premium look and ~70%
//                            smaller data URLs vs original PNG.
//
// Used by the admin Image Cropper's onCommit hook (no changes to the cropper
// itself). Pure function — safe to call from anywhere.

const clamp = (v) => (v < 0 ? 0 : v > 255 ? 255 : v);

const applyToneAdjustments = (imgData, { brightness, contrast, saturation }) => {
  const d = imgData.data;
  for (let i = 0; i < d.length; i += 4) {
    let r = d[i] * brightness;
    let g = d[i + 1] * brightness;
    let b = d[i + 2] * brightness;
    // contrast around midpoint
    r = (r - 128) * contrast + 128;
    g = (g - 128) * contrast + 128;
    b = (b - 128) * contrast + 128;
    // saturation — blend against luminance
    const lum = 0.2989 * r + 0.587 * g + 0.114 * b;
    r = lum + (r - lum) * saturation;
    g = lum + (g - lum) * saturation;
    b = lum + (b - lum) * saturation;
    d[i] = clamp(r);
    d[i + 1] = clamp(g);
    d[i + 2] = clamp(b);
  }
};

const unsharpMask = (imgData, strength) => {
  const w = imgData.width;
  const h = imgData.height;
  const src = imgData.data;
  const out = new Uint8ClampedArray(src.length);
  const k = strength;
  const center = 1 + 4 * k;
  for (let y = 0; y < h; y++) {
    for (let x = 0; x < w; x++) {
      const i = (y * w + x) * 4;
      if (x === 0 || y === 0 || x === w - 1 || y === h - 1) {
        out[i] = src[i];
        out[i + 1] = src[i + 1];
        out[i + 2] = src[i + 2];
        out[i + 3] = src[i + 3];
        continue;
      }
      const top = i - w * 4;
      const bot = i + w * 4;
      for (let c = 0; c < 3; c++) {
        const v =
          src[i + c] * center +
          src[i - 4 + c] * -k +
          src[i + 4 + c] * -k +
          src[top + c] * -k +
          src[bot + c] * -k;
        out[i + c] = clamp(v);
      }
      out[i + 3] = src[i + 3];
    }
  }
  return new ImageData(out, w, h);
};

const loadImage = (src) =>
  new Promise((resolve, reject) => {
    const img = new window.Image();
    img.crossOrigin = "anonymous";
    img.onload = () => resolve(img);
    img.onerror = () => reject(new Error("image load failed"));
    img.src = src;
  });

export const enhanceImage = async (sourceUrl, opts = {}) => {
  const {
    brightness = 1.04,
    contrast = 1.1,
    saturation = 1.12,
    sharpen = 0.35,
    maxDim = 1600,
    quality = 0.92,
  } = opts;

  const img = await loadImage(sourceUrl);

  // 1. Resolution balancing — downscale only if needed.
  let w = img.naturalWidth || img.width;
  let h = img.naturalHeight || img.height;
  const longest = Math.max(w, h);
  if (longest > maxDim) {
    const r = maxDim / longest;
    w = Math.round(w * r);
    h = Math.round(h * r);
  }
  if (w < 1 || h < 1) throw new Error("invalid image dimensions");

  const canvas = document.createElement("canvas");
  canvas.width = w;
  canvas.height = h;
  const ctx = canvas.getContext("2d");
  ctx.imageSmoothingEnabled = true;
  ctx.imageSmoothingQuality = "high";
  ctx.drawImage(img, 0, 0, w, h);

  // 2. Tone pass.
  let imageData = ctx.getImageData(0, 0, w, h);
  applyToneAdjustments(imageData, { brightness, contrast, saturation });
  ctx.putImageData(imageData, 0, 0);

  // 3. Sharpen pass (skip on very small images).
  if (sharpen > 0 && w >= 8 && h >= 8) {
    const sharpened = unsharpMask(
      ctx.getImageData(0, 0, w, h),
      Math.max(0, Math.min(1, sharpen)),
    );
    ctx.putImageData(sharpened, 0, 0);
  }

  // 4. Encode.
  const dataUrl = canvas.toDataURL("image/jpeg", quality);
  return {
    dataUrl,
    width: w,
    height: h,
    sizeKb: Math.round((dataUrl.length * 0.75) / 1024),
  };
};
